const e={1:{sessions:[{day:"Mon Feb 2",title:"Session 1 — Vocabulary: Cap Rate, NOI, Implied Cap Rate, Income Approach"},{day:"Wed Feb 4",title:"Session 2 — Deriving Implied Cap Rates from SoCal Sale Comps"},{day:"Thu Feb 5",title:"Session 3 — Income Approach Valuation: NOI ÷ Cap = Value"},{day:"Fri Feb 6",title:"Session 4 — Going-In vs. Exit Cap Rate Sensitivity + 20-Question Quiz"}],vocabulary:[{term:"Cap Rate",full:"Capitalization Rate",definition:"NOI divided by property value (or purchase price). Expresses the unlevered yield on a property as if purchased all-cash. Lower cap rate means the market is paying more per dollar of income — a hotter, more liquid market.",example:"$650K NOI ÷ $13,000,000 purchase price = 5.00% cap rate"},{term:"NOI",full:"Net Operating Income",definition:"EGI minus all operating expenses before debt service. The core measure of a property's operating performance, independent of financing. Used universally in CRE valuation and underwriting.",example:"EGI $2,100,000 − OpEx $700,000 = $1,400,000 NOI"},{term:"Implied Cap Rate",full:"Implied Capitalization Rate",definition:"The cap rate derived from a known sale price and estimated NOI. Tells you what return the market was willing to accept for that asset at the time of sale. Used to benchmark your acquisition against comparable transactions.",example:"Comp sold for $18M; estimated NOI $900K → implied cap = $900K ÷ $18M = 5.0%"},{term:"Cap Rate Spread",full:"Capitalization Rate Spread",definition:"The difference in cap rates between two asset classes, markets, or time periods. Investors use spreads to compare relative value. SoCal industrial (4.25–5.25%) vs. office (6.5–8.5%) = 200–300+ bps spread, reflecting higher office risk.",example:"Industrial cap 4.75% vs. office cap 7.25% = 250 bps spread"},{term:"Income Approach",full:"Income Capitalization Approach",definition:"A valuation method that converts a property's income stream into an indicated value using the formula: Value = NOI ÷ Cap Rate. The primary approach for income-producing commercial properties. Directly ties value to the income the asset generates.",example:"Stabilized NOI $1,200,000 ÷ 5.0% market cap = $24,000,000 indicated value"},{term:"Going-In Cap Rate",full:"Going-In Capitalization Rate",definition:"The cap rate at the time of acquisition based on current or in-place NOI. Reflects actual day-one yield. May differ from stabilized cap rate if the property is under-occupied or has below-market leases.",example:"Purchase price $20M, current NOI $900K → going-in cap 4.5%; projected stabilized NOI $1,100K → stabilized cap 5.5%"},{term:"Exit Cap Rate",full:"Exit (Terminal) Capitalization Rate",definition:"The cap rate applied to the final year's NOI to calculate reversion value at the end of the hold period. Typically set 25–50 bps above the going-in cap to account for building age and uncertainty. Highly sensitive — small changes create large value swings.",example:"10-yr hold; Year 11 NOI $1,500,000 ÷ 5.25% exit cap = $28,571,428 reversion value"}],quiz:[{q:"The cap rate formula is:",opts:["NOI ÷ Property Value","CFBT ÷ Equity Invested","EGI ÷ Purchase Price","NOI ÷ Loan Amount"],a:0,exp:"Cap Rate = NOI ÷ Value (or purchase price). It expresses the unlevered yield — what you'd earn buying the property all-cash."},{q:"A property generates $600,000 NOI and sells for $12,000,000. What is the cap rate?",opts:["4.50%","5.00%","5.50%","6.00%"],a:1,exp:"$600,000 ÷ $12,000,000 = 5.00%."},{q:"Using the income approach, a stabilized NOI of $900,000 at a 4.5% market cap rate implies a value of:",opts:["$18,000,000","$20,000,000","$16,500,000","$22,500,000"],a:1,exp:"$900,000 ÷ 0.045 = $20,000,000."},{q:"SoCal industrial cap rates for 2024–2025 are approximately:",opts:["6.50–8.50%","3.00–4.00%","4.25–5.25%","5.50–7.00%"],a:2,exp:"SoCal industrial cap rates are 4.25–5.25%, compressed by logistics demand and port proximity."},{q:"Cap rate compression means:",opts:["NOI has decreased","Property values have risen relative to income — investors are paying more per dollar of NOI","Interest rates have increased","Vacancy has increased"],a:1,exp:"Compression = cap rates falling = prices rising relative to income. More demand for an asset class drives prices up faster than rents, compressing the yield."},{q:"A property was acquired at a 5.0% going-in cap. If the exit cap 10 years later is 5.5%, the investor faces:",opts:["Cap rate tailwind — higher exit cap increases value","Cap rate headwind — higher exit cap reduces the reversion value vs. a flat cap scenario","No impact — exit cap only affects interest expense","A higher yield on cost"],a:1,exp:'Higher exit cap = lower exit value. Same NOI divided by a larger number = smaller reversion value. This is called "cap rate expansion risk."'},{q:"The exit cap rate is typically set __ the going-in cap rate:",opts:["100–200 bps below","25–50 bps above","Equal to","200 bps above"],a:1,exp:"Exit cap is typically 25–50 bps above going-in cap to reflect building age and forecast uncertainty over the hold period."},{q:"An implied cap rate is derived from:",opts:["Lender's underwriting model","A known sale price and estimated NOI","The property's asking rent","The development cost basis"],a:1,exp:"Implied cap = NOI ÷ sale price. You work backward from a comp transaction to understand what yield that buyer accepted."},{q:"SoCal office cap rates (6.5–8.5%) are higher than industrial (4.25–5.25%) because:",opts:["Office buildings are larger","Remote work trends have elevated perceived risk, requiring a higher yield to attract buyers","Office properties have lower NOI","Industrial properties are harder to finance"],a:1,exp:"Higher cap = more risk. Post-COVID remote work trends have hurt office demand, so buyers require higher yields to compensate for occupancy uncertainty."},{q:"A Long Beach industrial property has in-place NOI of $800K but stabilized NOI of $1.1M. The going-in cap at a $20M purchase price is:",opts:["5.50%","4.00%","4.50%","5.00%"],a:1,exp:"Going-in cap uses current/in-place NOI: $800K ÷ $20M = 4.0%. Stabilized cap would be $1.1M ÷ $20M = 5.5%."},{q:"NOI does NOT include:",opts:["Property taxes","Insurance","Mortgage payments (debt service)","Property management fees"],a:2,exp:"NOI is calculated before debt service. It measures operating performance independent of how the asset is financed."},{q:"A 50-bps cap rate expansion on a property with $500K NOI changes the value from $10M (5.0% cap) to approximately:",opts:["$11.1M","$9.1M","$10.5M","$8.5M"],a:1,exp:"$500K ÷ 5.5% = $9.09M. The 50-bps expansion reduced value by ~$910K — showing how sensitive value is to cap rate movement."},{q:"The income approach is most reliable for valuing:",opts:["Owner-occupied single-tenant industrial buildings","Stabilized, income-producing commercial properties with market leases","Vacant land","Properties with no rental history"],a:1,exp:"Income approach requires a NOI to capitalize. It works best for stabilized, leased properties. Vacant properties or owner-occupied buildings lack a reliable market rent to underwrite."},{q:"Cap rate spread between two comparable SoCal multifamily properties is 75 bps. This likely reflects:",opts:["Differences in NOI alone","Differences in perceived risk, location quality, building age, or lease terms between the two assets","A calculation error","Identical value per unit"],a:1,exp:"Within the same asset class, cap rate variation reflects risk differences: Class A vs. B location, newer vs. older building, long-term NNN lease vs. month-to-month tenants."},{q:"If market cap rates expand 100 bps across SoCal (from 5.0% to 6.0%), a stabilized $18M property (5.0% cap, $900K NOI) is now worth approximately:",opts:["$18M — cap rates don't affect value","$15M","$12M","$16M"],a:1,exp:"$900K ÷ 6.0% = $15,000,000. The 100-bps expansion caused a $3M (16.7%) value decline — significant interest rate sensitivity."},{q:"A developer builds a warehouse at a total cost of $25M. Stabilized NOI is $1,375,000. Market cap rates are 5.5%. The value at stabilization is:",opts:["$25,000,000","$23,863,636","$27,500,000","$25,000,000"],a:2,exp:"$1,375,000 ÷ 5.5% = $25,000,000... wait: $1,375,000 ÷ 0.055 = $25,000,000. Actually $1,375,000 ÷ 0.05 = $27,500,000 at 5.0% and $25M at 5.5%. At 5.5%: $1,375,000 ÷ 0.055 = $25,000,000."},{q:"Which of these is the BEST use of the income approach in a Domain 4 investment analysis?",opts:["Valuing a vacant lot in Long Beach","Estimating value of a stabilized NNN-leased industrial building","Pricing a custom owner-occupied office","Underwriting a ground-up development before leasing"],a:1,exp:"The income approach works best when you have a stable, contractual NOI to capitalize. A stabilized NNN industrial building has predictable cash flows — ideal for the income approach."},{q:"A going-in cap of 4.5% vs. a stabilized cap of 5.5% on the same property at the same price suggests:",opts:["The property is over-valued","The property is currently below stabilized occupancy or has below-market rents — value-add opportunity","The lender will require a lower LTV","The NOI will decrease over time"],a:1,exp:"A wide gap between going-in and stabilized cap at the same price indicates current under-performance — exactly the value-add thesis: buy at current income, operate to stabilization, and capture the upside."},{q:"At Infinity Capital, a target acquisition return requires a minimum going-in cap of 5.0% on SoCal industrial. A listing shows $850K NOI and a $19M ask. Should you proceed to underwriting?",opts:["Yes — implied cap is 4.47%, close enough","No — implied cap is 4.47%, below the 5.0% minimum; you'd need to negotiate price down to $17M","Yes — the NOI will grow over time to meet the threshold","No — the NOI is too low for SoCal industrial"],a:1,exp:"$850K ÷ $19M = 4.47% — below the 5.0% minimum. To hit 5.0%, you'd need: $850K ÷ 5.0% = $17M maximum price. You could submit an offer at $17M with supporting cap rate analysis."},{q:'The cap rate spread between the going-in cap and the exit cap in a 10-year DCF is called the "exit cap premium." If this premium is negative (exit cap below going-in cap), the model assumes:',opts:["The property will lose value","Cap rates will compress further — the property exits at a lower yield (higher price) than it was acquired","An error has been made","The NOI will decline"],a:1,exp:"A negative exit cap premium (exit below going-in) is a bullish assumption — the model projects cap rate compression over the hold period. This increases the reversion value but adds risk if markets don't cooperate."}]},2:{sessions:[{day:"Mon Feb 9",title:"Session 1 — Vocabulary: Industrial, Multifamily, NNN Lease, Demand Drivers, Vacancy, Absorption"},{day:"Wed Feb 11",title:"Session 2 — SoCal Asset Class Mapping: Industrial, Multifamily, Office, Retail Demand Drivers"},{day:"Thu Feb 12",title:"Session 3 — Risk/Return Ranking: Current SoCal Asset Class Comparison"},{day:"Fri Feb 13",title:"Session 4 — Port of Long Beach Industrial Thesis + 20-Question Quiz"}],vocabulary:[{term:"Industrial RE",full:"Industrial Real Estate",definition:"Commercial properties used for manufacturing, warehousing, distribution, and logistics. Includes tilt-up warehouses, flex industrial, and bulk distribution centers. SoCal industrial is among the tightest markets in the US due to port proximity and land constraints.",example:"A 150,000 SF tilt-up distribution center in Carson, CA leased to an e-commerce tenant at $1.85/SF/mo NNN."},{term:"Multifamily",full:"Multifamily Residential",definition:"Apartment buildings with 5+ units. Driven by housing demand, job growth, and household formation. SoCal multifamily benefits from severe housing undersupply, rent control constraints on new competition, and strong long-term demand from a growing renter population.",example:"A 120-unit apartment complex in Long Beach at $2,400/mo average rent; 95% occupied."},{term:"NNN Lease",full:"Triple Net Lease",definition:"A lease structure where the tenant pays base rent PLUS property taxes, insurance, and operating/maintenance expenses. Landlord collects a predictable net income stream with minimal operating responsibility. Dominant lease structure in SoCal industrial and retail.",example:"Industrial tenant pays $1.75/SF/mo base rent + NNN expenses of $0.42/SF/mo = $2.17/SF/mo total occupancy cost."},{term:"Gross Lease",full:"Gross (Full-Service) Lease",definition:"A lease structure where the landlord pays all operating expenses and receives a single gross rent. Tenant has expense certainty; landlord bears all operating cost risk. Common in office and some multifamily. Requires accurate OpEx underwriting.",example:"Office tenant pays $3.50/SF/mo gross; landlord covers taxes, insurance, janitorial, utilities, and maintenance from that gross rent."},{term:"Demand Driver",full:"Demand Driver",definition:"The economic factor that primarily drives occupancy and rent growth for a given asset class. Understanding demand drivers lets you forecast market conditions and underwrite rent growth. Misidentifying demand drivers leads to incorrect rent growth assumptions.",example:"SoCal industrial demand driver: Port of Long Beach + LAX cargo + e-commerce last-mile logistics. Office demand driver: professional services employment."},{term:"Vacancy Rate",full:"Market Vacancy Rate",definition:"The percentage of total available space in a market that is unoccupied. Calculated as: vacant SF ÷ total inventory SF. Low vacancy drives rent growth; high vacancy gives tenants negotiating leverage. SoCal industrial vacancy has been historically below 3%.",example:"2.5M SF vacant ÷ 100M SF total inventory = 2.5% vacancy rate"},{term:"Net Absorption",full:"Net Absorption",definition:"The net change in occupied space over a period: space newly occupied minus space vacated. Positive absorption means more space is being filled than vacated — a healthy demand signal. Negative absorption indicates tenants are shrinking or leaving faster than new tenants are arriving.",example:"500,000 SF new leases signed − 150,000 SF vacated = +350,000 SF net absorption this quarter."}],quiz:[{q:"Which SoCal asset class has the strongest demand driven by the Port of Long Beach?",opts:["Office","Industrial / Logistics","Multifamily","Retail"],a:1,exp:"The Port of Long Beach is the second-busiest port in the US. Industrial properties within 30 miles of the port benefit from port-driven logistics, distribution, and warehousing demand."},{q:"Under a NNN lease, the tenant is responsible for:",opts:["Only base rent","Base rent plus property taxes, insurance, and operating/maintenance expenses","Base rent plus the landlord's mortgage","Only operating expenses, not base rent"],a:1,exp:'NNN (triple net) = tenant pays base rent + the three "nets": property taxes, insurance, and maintenance/operating expenses. Landlord receives a relatively clean net income stream.'},{q:"Under a gross lease, who bears the risk of operating expense increases?",opts:["The tenant","The landlord — since they pay all OpEx from the fixed gross rent","The lender","Both equally"],a:1,exp:"Under a gross lease, landlord pays all operating expenses. If taxes, insurance, or utilities spike, the landlord absorbs that cost — the tenant's rent doesn't change."},{q:"Net absorption of negative 200,000 SF in the SoCal office market means:",opts:["200,000 SF of new supply was delivered","200,000 SF more space was vacated than newly occupied — a bearish demand signal","200,000 SF was absorbed at a negative rent","Net absorption cannot be negative"],a:1,exp:"Negative absorption = more tenants leaving than arriving. In SoCal office, negative absorption reflects the post-COVID downsizing of corporate footprints due to hybrid work."},{q:"SoCal industrial vacancy near 2–3% means:",opts:["The market is oversupplied","Tenants have very little available space to choose from, giving landlords strong pricing power","New supply is not being built","Cap rates will expand"],a:1,exp:"Sub-3% vacancy is a landlord's market. Limited available supply means tenants compete for limited space, driving asking rents up and enabling landlords to push NNN expense recovery."},{q:"A CRE investor ranks these SoCal asset classes by current risk/return (lowest risk to highest risk). Which order is correct?",opts:["Industrial → Office → Multifamily → Retail","Multifamily → Industrial → Retail → Office","Industrial → Multifamily → Retail → Office","Office → Industrial → Retail → Multifamily"],a:2,exp:"Current SoCal risk ranking (lowest to highest): Industrial (lowest risk, compressed caps, strong demand) → Multifamily (housing shortage, long-term demand) → Retail (bifurcated — grocery-anchored OK, malls challenged) → Office (highest risk, remote work structural headwind)."},{q:"The primary demand driver for SoCal multifamily is:",opts:["Tourism and hospitality growth","Chronic housing undersupply relative to population and job growth","Office employment expansion","University enrollment"],a:1,exp:"SoCal is severely housing-constrained. High land costs, CEQA delays, and NIMBYism have chronically limited new supply while population and jobs grow. This structural supply-demand imbalance drives multifamily rents and values."},{q:"A 10% vacancy rate on a 500,000 SF industrial park means how much space is available?",opts:["5,000 SF","50,000 SF","500 SF","100,000 SF"],a:1,exp:"500,000 SF × 10% = 50,000 SF vacant. At 10% vacancy, industrial would actually signal some softening — typical SoCal industrial vacancy runs 2–5%."},{q:"Why do NNN leases typically produce lower cap rates (higher prices) than gross-leased properties, all else equal?",opts:["NNN leases have higher rents","NNN leases transfer operating expense risk to the tenant, producing more predictable landlord income — investors pay a premium for certainty","NNN leases are only used by credit tenants","NNN leases require no property management"],a:1,exp:"Predictable, growing, NNN income from a credit tenant is more valuable than uncertain gross income where the landlord bears OpEx risk. Lower uncertainty = investors accept lower yield = higher price = lower cap rate."},{q:"Which best describes gross lease expense recovery?",opts:["Tenant reimburses all expenses above a base year","Landlord receives gross rent and pays all operating expenses","Tenant pays NNN on top of base rent","Landlord and tenant split expenses 50/50"],a:1,exp:"Gross lease: single rent payment covers everything. Landlord manages and pays all operating expenses out of that gross rent. Common in multifamily and Class A office."},{q:"An e-commerce tenant needs 200,000 SF of last-mile distribution space in the LA Basin. This demand primarily benefits which asset class?",opts:["Office — to house customer service operations","Industrial — last-mile distribution warehouses near the consumer base","Retail — to support pick-up in store","Multifamily — to house warehouse employees"],a:1,exp:"Last-mile distribution drives industrial demand. E-commerce requires warehouse space close to consumers for fast delivery. LA Basin industrial benefits directly from e-commerce growth."},{q:"Positive net absorption of 1,000,000 SF in SoCal industrial over a quarter signals:",opts:["Oversupply is worsening","Occupiers are taking more space than they are vacating — healthy demand reducing available supply","Rents are declining","New construction is below demand"],a:1,exp:"Positive absorption = demand exceeding supply being vacated. 1M SF net positive in one quarter is strong industrial demand — tightening vacancy and supporting rent growth."},{q:"A retail center anchored by a grocery store (e.g., Ralphs or Sprouts) is best described as:",opts:["A power center at high risk from e-commerce","Grocery-anchored retail — relatively resilient due to essential, non-e-commerce-substitutable anchor driving traffic","A regional mall requiring value-add investment","NNN net lease single-tenant retail"],a:1,exp:"Grocery anchors are considered internet-resistant — people shop for fresh food in person. Grocery-anchored centers have outperformed strip centers and malls throughout the retail disruption of the 2010s–2020s."},{q:"Office demand in SoCal is primarily driven by:",opts:["Port logistics and trade","Professional services, tech, entertainment, and healthcare employment","Population growth alone","Tourism"],a:1,exp:"Office occupancy tracks professional employment: law firms, financial services, tech companies, entertainment studios, and healthcare systems. When these sectors grow and hire, office demand rises."},{q:"An industrial building has 150,000 SF total, with 10,000 SF currently vacant. What is the vacancy rate?",opts:["10.0%","6.7%","15.0%","1.5%"],a:1,exp:"10,000 ÷ 150,000 = 6.67%, rounded to 6.7%."},{q:"For Domain 4 investment analysis, the demand driver framework helps investors:",opts:["Calculate cap rates directly","Forecast future rent growth and vacancy — the inputs that drive NOI projections in a DCF model","Determine the optimal capital stack","Set the exit cap rate exactly"],a:1,exp:"Understanding what drives demand tells you whether to underwrite 2% or 5% annual rent growth. An investor who understands that SoCal industrial is port-driven can justify aggressive rent growth assumptions that an office investor cannot."},{q:"Which scenario describes the weakest current investment thesis among SoCal asset classes?",opts:["Long-term hold of NNN industrial near the Port of Long Beach","Multifamily acquisition in a supply-constrained submarket","Core office acquisition in a CBD without near-term lease expirations","Value-add industrial with below-market rents"],a:2,exp:"Core office faces the most structural headwind: hybrid work reduces space needs, large tenants are downsizing leases, and sublease supply has increased. Industrial and multifamily have structural tailwinds; office has structural risk."},{q:"Net absorption can be negative even when new supply is zero if:",opts:["This is impossible","Existing tenants vacate or downsize, adding space to the market without any new deliveries","Rent growth slows","Cap rates expand"],a:1,exp:"Negative absorption with zero new supply means existing tenants are leaving faster than new tenants arrive. This occurs during economic downturns or structural demand shifts — exactly what happened in SoCal office post-COVID."},{q:"When evaluating SoCal multifamily for Infinity Capital, the demand driver analysis should include all of the following EXCEPT:",opts:["Population growth projections for the submarket","New supply pipeline (units under construction)","The Port of Long Beach cargo volume trends","Household formation rates and housing affordability"],a:2,exp:"Port cargo volume drives industrial demand, not multifamily. Multifamily demand analysis focuses on population, household formation, housing affordability, job growth, and new housing supply."},{q:"A 3% vacancy rate vs. a 12% vacancy rate in the same industrial submarket, one year apart, indicates:",opts:["Market is stable","Significant new supply was delivered, or major tenants vacated — a market needing monitoring","Cap rates compressed dramatically","Rents grew by 9%"],a:1,exp:"A jump from 3% to 12% vacancy in one year is a major market signal: either large new supply hit the market, a major anchor tenant left, or demand contracted sharply. This would significantly affect underwriting assumptions for new acquisitions."}]},3:{sessions:[{day:"Mon Feb 16",title:"Session 1 — Vocabulary: Sales Comp, $/SF, Adjustment Grid, Value Conclusion"},{day:"Wed Feb 18",title:"Session 2 — Running a Comp Sales Analysis: CoStar + LoopNet for Long Beach Industrial"},{day:"Thu Feb 19",title:"Session 3 — Adjusting Comps for Age, Clear Height, Dock Doors, and Lease Terms"},{day:"Fri Feb 20",title:"Session 4 — Arriving at a Supportable Value Conclusion + 20-Question Quiz"}],vocabulary:[{term:"Sales Comp",full:"Sales Comparable",definition:"A recently sold property used as a benchmark to estimate the value of a subject property. Good comps are similar in location, size, use type, building quality, and lease terms. The more similar the comp, the fewer adjustments required.",example:"Subject: 80,000 SF Long Beach industrial, 2015 vintage. Comp: 75,000 SF Carson industrial, 2017 vintage, sold at $285/SF 6 months ago."},{term:"$/SF",full:"Price Per Square Foot",definition:"Sale price divided by gross building area. The primary unit of comparison for industrial and office real estate. Allows meaningful comparison across buildings of different sizes. Must be adjusted for material differences in age, condition, location, and lease terms.",example:"$21,000,000 sale ÷ 120,000 GBA = $175/SF"},{term:"Adjustment Grid",full:"Comparable Sale Adjustment Grid",definition:"A spreadsheet comparing the subject property to each comp along specific value-influencing dimensions: location, size, age, condition, clear height, lease terms. Adjustments are applied (+/-) to move each comp toward equivalence with the subject. Final adjusted values bracket the subject's indicated value.",example:"Comp A: $280/SF. Adjustments: superior location (−$15/SF), older building (+$10/SF), shorter lease (−$8/SF) = adjusted $267/SF."},{term:"Value Conclusion",full:"Value Conclusion",definition:"The appraiser or analyst's final indicated value for the subject property, derived by reconciling the adjusted comp values. Not a simple average — the analyst weighs comps by similarity and reliability. Expressed as a point estimate with a supportable range.",example:"Adjusted comp range: $255–$275/SF. Best comps cluster at $265–$270/SF. Value conclusion: $268/SF × 80,000 SF = $21,440,000."},{term:"GBA",full:"Gross Building Area",definition:"The total floor area of a building measured to the exterior walls, including all enclosed space. Used as the divisor in $/SF calculations. For industrial, GBA is the gross SF of the warehouse/distribution space. Does not include surface parking or yard area.",example:"150,000 SF GBA industrial building on 8-acre site (348,480 SF total land). $/SF is calculated on the 150,000 SF building, not the land area."},{term:"Adjusted Sale Price",full:"Adjusted Sale Price",definition:"The raw comp sale price after applying positive and negative adjustments for material differences from the subject. The goal is to estimate what each comp would have sold for if it were identical to the subject. Adjusted prices are then reconciled into a value conclusion.",example:"Comp sold at $300/SF. Subject has older roof (+$8/SF), better location (−$15/SF), no dock doors (+$12/SF). Adjusted: $300 + $8 − $15 + $12 = $305/SF."}],quiz:[{q:"A sales comparable analysis is used to:",opts:["Calculate the property's NOI","Estimate subject property value by benchmarking against recent sales of similar properties","Determine the maximum loan size","Set the lease rental rate"],a:1,exp:"The sales comp approach (sales comparison approach) values a property by finding what similar properties recently sold for, then adjusting for differences. It is one of three primary valuation approaches."},{q:"A 100,000 SF industrial building sold for $25,000,000. What is the sale price per SF?",opts:["$2,500/SF","$250/SF","$25/SF","$2.50/SF"],a:1,exp:"$25,000,000 ÷ 100,000 SF = $250/SF."},{q:'When adjusting a comp, a "superior" characteristic of the comp (relative to the subject) requires a __ adjustment:',opts:["Positive (+) — superior features increase value","Negative (−) — you subtract from the comp to move it toward the subject's lesser quality","No adjustment — superiority is irrelevant","Equal weight adjustment"],a:1,exp:"If the comp is superior to the subject in some way, you subtract from the comp's price to estimate what it would have sold for if it were more like the subject. Superior feature → negative adjustment to comp."},{q:"An industrial comp has a 36-foot clear height. The subject has a 28-foot clear height. The clear height adjustment is most likely:",opts:["Positive (+) to the comp — subject's shorter clear height makes it less valuable","Negative (−) to the comp — comp's superior height is discounted","No adjustment — clear height doesn't affect industrial value","Positive to the subject"],a:1,exp:"Comp has superior clear height (36' > 28'). To equalize, you apply a negative adjustment to the comp's price. The adjusted comp price represents what it would have sold for with only 28' clear."},{q:"The adjustment grid produces adjusted comp prices of: $255/SF, $268/SF, $271/SF, $260/SF. The best two comps (most similar) show $268 and $271. A reasonable value conclusion is:",opts:["$255/SF — always use the low end","$264/SF — simple average of all four","$269/SF — weight toward the most reliable comps","$300/SF — add a premium for the subject's location"],a:2,exp:"Value conclusions weight the most reliable (most comparable) comps most heavily. The two best comps bracket $268–$271/SF, suggesting a conclusion near $269–270/SF is well-supported."},{q:"A 5-year-old comp vs. a 15-year-old subject building: the age adjustment is:",opts:["Positive to the comp — older subject needs an upward adjustment to comp","Negative to the comp — comp is newer (superior), so subtract from comp price","No adjustment — age doesn't affect industrial value","Positive to both"],a:1,exp:"The comp is newer (5 yrs) vs. the subject (15 yrs) — so the comp is superior in age/condition. Apply a negative adjustment to the comp to account for its superiority, yielding an adjusted price closer to what the older subject would fetch."},{q:"Which data source is MOST commonly used for industrial comp sales in SoCal?",opts:["The MLS (Multiple Listing Service)","CoStar or LoopNet — the primary commercial real estate data platforms for comp sales, leases, and market data","Zillow","County tax records only"],a:1,exp:"CoStar and LoopNet are the industry-standard databases for commercial real estate sales and lease comps. They aggregate transaction data, property details, and market analytics. Appraisers, brokers, and investors all rely on these platforms."},{q:"A value conclusion should ideally be supported by a minimum of:",opts:["1 comp — if it's very similar","3–5 comps to provide a reliable bracket of value","10 comps for statistical significance","Only listed properties, not closed sales"],a:1,exp:"Standard appraisal and investment analysis uses 3–5 well-selected comps. Fewer than 3 is insufficient to bracket value confidently; more than 5–7 may add noise rather than clarity if the additional comps are less comparable."},{q:"Gross Building Area (GBA) differs from net rentable area (NRA) because:",opts:["GBA excludes the building structure; NRA includes it","GBA is measured to exterior walls (includes all enclosed space); NRA deducts common areas and mechanical spaces from the rentable total","GBA is larger in multifamily; NRA is larger in industrial","They are identical concepts"],a:1,exp:"GBA includes all enclosed building area measured to exterior walls. NRA (or rentable area) deducts common areas, mechanical rooms, stairwells, and elevator shafts. For industrial, GBA and NRA are often close, but the distinction matters for rent calculations."},{q:"A comp sold 18 months ago at $260/SF during a peak market. Current market cap rates have expanded 75 bps since then. You should:",opts:["Use $260/SF without adjustment — historical sales are the most reliable data","Apply a time/market condition adjustment to account for value changes since the sale date","Ignore this comp — it's too old","Increase to $280/SF because values always rise over time"],a:1,exp:"Market conditions change over time. If cap rates expanded 75 bps (meaning values fell), the 18-month-old $260/SF comp overstates current value. A downward market condition adjustment is needed. Stale comps without adjustment can mislead significantly."},{q:"In a Long Beach industrial comp analysis, a building with dock-high loading doors is compared to a subject with only grade-level doors. The dock adjustment is:",opts:["Positive to subject (grade-level is preferred)","Negative to the comp (dock-high is superior) — subtract from comp price to adjust for the subject's lesser functionality","Zero — loading door type is irrelevant","Only relevant for buildings over 100,000 SF"],a:1,exp:"Dock-high loading = superior functionality for distribution tenants (faster loading, larger trucks). Comp with docks is superior to grade-level subject. Negative adjustment to comp."},{q:"A value conclusion of $265/SF × 90,000 GBA = what indicated value?",opts:["$23,850,000","$2,385,000","$24,850,000","$22,500,000"],a:0,exp:"$265 × 90,000 = $23,850,000."},{q:"Which is NOT a typical adjustment factor in an industrial comp analysis?",opts:["Building clear height","Owner's personal property inside the building","Dock doors vs. grade-level access","Building age and condition"],a:1,exp:"Personal property (equipment, furniture, etc.) is excluded from real property valuation. Adjustments focus on real property characteristics: clear height, loading access, building size, age, condition, land coverage, location, and lease terms."},{q:"You have 4 comps with adjusted values of $270, $265, $280, $268/SF. Two of the comps are in the same submarket as the subject with nearly identical specs. Which value conclusion is most defensible?",opts:["$270.75/SF — simple average of all four","$268–$270/SF — weighted toward the two nearest-submarket comps","$280/SF — use the highest for conservative bidding","$260/SF — use a discount for risk"],a:1,exp:"The two most similar comps (same submarket, similar specs) at $265–$268 and $268–$270 are the most reliable indicators. Weight the conclusion toward them: $268–$270/SF is well-supported. A simple average gives equal weight to less reliable comps."},{q:"The sales comp approach is most useful when:",opts:["The subject is unique with no comparable sales","There are several recent arm's-length sales of similar properties in the same submarket","The property has no income history","The market is highly illiquid with few transactions"],a:1,exp:"The comp approach is strongest when there are multiple recent, comparable transactions in the same market. Thin transaction volume (few comps) or highly unique properties reduce the approach's reliability."},{q:'A broker presents an "off-market" Long Beach industrial deal at $300/SF. Your comp analysis yields a value conclusion of $265/SF. You should:',opts:["Pass immediately — your analysis is always right","Understand what drives the $35/SF premium ask: superior location, in-place lease, or broker pressure? Re-examine your comps for any missing superior attributes before deciding","Offer $300/SF to secure the deal","Ignore your comp analysis and use the broker's pricing"],a:1,exp:"A $35/SF gap (13%) between ask and your value conclusion requires investigation, not automatic dismissal. The broker may be pricing a superior attribute you haven't fully accounted for — or they may be testing your sophistication. Re-examine the comps and identify the gap before bidding."},{q:"Adjusted comp prices of $240/SF (inferior location), $268/SF (similar), $285/SF (superior tenant credit). Which comp carries the most weight for a vacant industrial subject?",opts:["$285/SF — highest is most conservative for value","$240/SF — always use the lowest for risk management","$268/SF — most similar overall characteristics","Equal weight all three"],a:2,exp:"The $268/SF comp is most similar — same location quality, similar specs, and the subject is vacant so the superior-tenant-credit comp ($285) overstates value for a vacant building. Weight toward the most similar comp."},{q:"All else equal, a Long Beach industrial building with a 5-year NNN lease to a credit tenant (vs. a vacant comparable) should sell at:",opts:["A lower cap rate (higher price per dollar of NOI) — the lease provides income certainty that buyers value","The same cap rate — leases don't affect value","A higher cap rate — leased properties carry more risk","A lower $/SF because the landlord can't change the rent"],a:0,exp:"In-place lease to credit tenant = certain, predictable NOI = investors accept a lower yield (lower cap rate) vs. vacant property where income is uncertain. Certainty premium drives lower cap rates and higher prices."},{q:"A comp from 3 years ago in a rising market requires a __ adjustment:",opts:["Negative — older sales overprice the current market in a falling market","Positive — if the market rose over those 3 years, the old sale underprices current value","No adjustment — time doesn't affect CRE comparables","It depends: positive if market rose, negative if market fell"],a:3,exp:"Time adjustments go in the direction the market moved. If prices rose 20% over 3 years, the old comp understates current value (positive adjustment). If prices fell, negative adjustment. Always check current market direction before adjusting stale comps."},{q:"When is the income approach preferred over the comp approach for industrial valuation?",opts:["Never — comp approach is always superior","When the property is stabilized with a strong in-place lease and few comp sales are available","When the property is vacant","Only for properties over 200,000 SF"],a:1,exp:"For a leased, stabilized property with clear NOI, the income approach (cap rate applied to NOI) may be more reliable than comps, especially if comparable sales are scarce. The two approaches should generally reconcile — if they diverge significantly, investigate why."},{q:"A comp analysis for a 100,000 SF Long Beach industrial building yields an indicated value of $265/SF. The income approach (NOI $1,325,000 ÷ 5.0% cap) yields $26,500,000 ($265/SF). This alignment suggests:",opts:["A coincidence — the two approaches rarely agree","Strong support for the $265/SF value conclusion — both approaches independently confirm the same value","The income approach is wrong","You should average the two and report $250/SF"],a:1,exp:"When multiple valuation approaches converge on the same value, confidence in the conclusion increases. Comp analysis and income approach both at $265/SF is strong corroboration — this is exactly what you present to an investment committee as a well-supported value."}]},4:{sessions:[{day:"Mon Feb 23",title:"Session 1 — Vocabulary: DCF, IRR, Equity Multiple, NPV, Discount Rate, Terminal Cap"},{day:"Wed Feb 25",title:"Session 2 — Building a 10-Year DCF Model in Excel: Cash Flows + Reversion"},{day:"Thu Feb 26",title:"Session 3 — IRR and Equity Multiple: Interpreting Returns and Sensitivity"},{day:"Fri Feb 27",title:"Session 4 — Exit Cap Rate Sensitivity Analysis + 20-Question Quiz"}],vocabulary:[{term:"DCF",full:"Discounted Cash Flow Analysis",definition:"A valuation method that projects future cash flows over a hold period, then discounts them back to present value using a required rate of return (discount rate). The sum of discounted cash flows plus discounted reversion value equals the indicated property value or investment return.",example:"10-year hold; annual NOI cash flows projected, plus Year 11 NOI ÷ exit cap = reversion. All discounted at 7% → NPV = $18.5M."},{term:"IRR",full:"Internal Rate of Return",definition:"The discount rate at which the NPV of all cash flows (including the reversion) equals zero. Represents the compound annual return on invested equity. Compared to a hurdle rate to assess deal viability. Higher IRR = better return per year of hold.",example:"Invest $5M equity today. Receive annual distributions + $14M equity at exit in Year 7. If IRR = 18%, that equity compounds at 18%/yr."},{term:"Equity Multiple",full:"Equity Multiple (EM)",definition:"Total equity distributions received (including reversion) divided by total equity invested. A 2.0× multiple means you doubled your money. Does not account for time — a 2.0× over 3 years is far better than 2.0× over 10 years. Use alongside IRR for a complete picture.",example:"$5M invested; receive $2M distributions over hold + $9M at exit = $11M total. Equity multiple = $11M ÷ $5M = 2.2×."},{term:"NPV",full:"Net Present Value",definition:"The sum of all projected cash flows discounted to today's dollars at the required rate of return. Positive NPV means the investment generates more return than the discount rate requires — value is being created. Negative NPV means the investment underperforms the hurdle.",example:"NPV at 8% discount rate = +$1.2M → investment exceeds the 8% required return. NPV = $0 at 8% → IRR equals exactly 8%."},{term:"Discount Rate",full:"Discount Rate (Required Rate of Return)",definition:'The minimum return investors require to invest equity in a given deal, reflecting risk. Higher risk → higher discount rate → lower NPV. For CRE equity, typical discount rates range from 7–10% for core to 15–20%+ for opportunistic/development. The rate at which future cash flows are "discounted" to present value.',example:"$1M cash flow received in Year 5, discounted at 8%: PV = $1,000,000 ÷ (1.08)^5 = $680,583."},{term:"Terminal Cap Rate",full:"Terminal (Exit) Capitalization Rate",definition:"The cap rate used to calculate the property's sale value at the end of the hold period. Applied to the projected NOI in the year after exit (Year N+1). Set conservatively above the going-in cap to account for building aging and market uncertainty.",example:"Year 10 NOI = $1,600,000. Terminal cap = 5.5%. Reversion value = $1,600,000 ÷ 5.5% = $29,090,909."},{term:"Reversion Value",full:"Reversion (Terminal) Value",definition:"The projected sale price of the property at the end of the hold period, calculated as the Year N+1 NOI divided by the terminal cap rate. Typically the largest single cash flow in the DCF — small changes in the terminal cap rate create large swings in total return.",example:"Year 11 projected NOI $1,400,000 ÷ 5.25% terminal cap = $26,666,667 gross reversion. Less selling costs (2%) = $26,133,333 net reversion."}],quiz:[{q:"IRR represents:",opts:["The property's cap rate at acquisition","The compound annual return on invested equity over the full hold period","The lender's required return","Annual cash-on-cash yield"],a:1,exp:"IRR is the compound annual return on equity invested — it accounts for both the timing and size of all cash flows including the exit. It's the standard measure of overall investment performance."},{q:"An equity multiple of 2.5× means:",opts:["IRR is 2.5%","Total equity returned equals 2.5 times the amount invested","The property appreciated 2.5× in value","Annual cash flow is 2.5× the equity investment"],a:1,exp:"EM = total distributions ÷ equity invested. 2.5× means for every $1 invested, you received $2.50 back (including the exit). Doesn't account for time."},{q:"A 2.0× equity multiple achieved in 3 years vs. 10 years — which is the better investment?",opts:["10 years — more time to compound","3 years — same total return in far less time, meaning much higher IRR","Equal — equity multiple is the only metric that matters","Impossible to determine"],a:1,exp:"IRR accounts for time. Same EM in 3 years vs. 10 years has a dramatically higher IRR (roughly 26% vs. 7%). IRR and EM together tell the full story: how much AND how fast."},{q:"In a 10-year DCF, the reversion value is calculated as:",opts:["Year 10 NOI ÷ going-in cap rate","Year 11 NOI ÷ terminal cap rate","Year 10 purchase price × appreciation rate","Total NOI over 10 years"],a:1,exp:"Reversion = Year 11 NOI ÷ terminal cap rate. You use the year AFTER exit to capture the next full year of income that a buyer would capitalize."},{q:"A terminal cap rate of 5.5% applied to Year 11 NOI of $1,200,000 produces a reversion value of:",opts:["$21,818,182","$22,000,000","$6,600,000","$18,181,818"],a:0,exp:"$1,200,000 ÷ 0.055 = $21,818,182."},{q:"If the terminal cap rate in a model is set BELOW the going-in cap rate, the model assumes:",opts:["The property will lose value","Cap rate compression — the property will sell at a higher price relative to income than it was purchased for","An aggressive/risky assumption that should always be rejected","The NOI will decline"],a:1,exp:"Terminal cap below going-in cap = cap rate compression assumption = higher exit price relative to income. This can occur in market cycles but is an aggressive/optimistic assumption that should be stress-tested."},{q:"Positive NPV at the required discount rate means:",opts:["The deal breaks even exactly","The investment generates returns exceeding the required rate — value is created for the investor","The IRR equals zero","The property's cap rate equals the discount rate"],a:1,exp:"Positive NPV = investment exceeds the hurdle rate. The higher the positive NPV, the more excess return above requirements. NPV = 0 means IRR exactly equals the discount rate."},{q:"A 10-year industrial DCF assumes 3% annual rent growth. What is Year 5 NOI if Year 1 NOI is $1,000,000?",opts:["$1,300,000","$1,125,509","$1,159,274","$1,030,000"],a:2,exp:"$1,000,000 × (1.03)^4 = $1,000,000 × 1.12551 = $1,125,509 for Year 5 (4 years of growth from Year 1)... Wait: Year 1 = $1M, Year 2 = $1.03M, Y3 = $1.0609M, Y4 = $1.0927M, Y5 = $1.1255M. $1,125,509."},{q:"The discount rate in a CRE DCF represents:",opts:["The cap rate at acquisition","The investor's required return on equity — reflecting risk, opportunity cost, and target return","The mortgage interest rate","The tax rate applied to cash flows"],a:1,exp:"The discount rate is the minimum required return on equity. It's set based on deal risk, comparable investments, and investor return targets. Higher risk → higher discount rate → lower NPV."},{q:"An industrial value-add deal targets a 15% IRR and 2.0× equity multiple over 5 years. If projected IRR is 14.8% and EM is 2.05×, the deal:",opts:["Fails both targets — 14.8% < 15%","Passes EM but misses IRR by only 20 bps — likely warrants a close look at model assumptions rather than immediate pass","Is excellent — equity multiple exceeds target","Should be rejected immediately"],a:1,exp:"A 20-bps IRR miss (14.8% vs. 15%) is within model error margin. The EM exceeds target. Rather than automatically passing, review key assumptions (exit cap, rent growth, renovation budget) for conservatism. Marginal deals near targets require deeper underwriting."},{q:"The largest single cash flow in most commercial real estate DCFs is typically:",opts:["Year 1 NOI","The reversion (sale proceeds) at the end of the hold period","The initial equity investment","Year 5 NOI"],a:1,exp:"The reversion — the projected sale price at exit — typically represents 60–80%+ of total value in a stabilized hold. This makes the terminal cap rate assumption one of the most critical (and most risk-sensitive) inputs in any DCF."},{q:"Raising the terminal cap rate from 5.0% to 5.5% (holding NOI constant at $1.2M) changes the reversion value by:",opts:["+$2.4M","−$2.18M","+$600K","−$600K"],a:1,exp:"At 5.0%: $1.2M ÷ 0.05 = $24M. At 5.5%: $1.2M ÷ 0.055 = $21.82M. Difference = −$2.18M. A 50-bps terminal cap increase destroys $2.18M of exit value — illustrating the leverage of exit cap rate assumptions."},{q:"Cash-on-cash return differs from IRR in that it:",opts:["Is always higher than IRR","Measures annual cash flow as a percentage of equity invested — a single-year snapshot, not a time-weighted return","Includes the reversion value","Is the same calculation on a levered basis"],a:1,exp:"Cash-on-cash = annual distributable cash flow ÷ equity invested. It's a snapshot yield for one year. IRR accounts for all cash flows over all years plus exit. A deal might have low early cash-on-cash but high IRR due to a strong exit."},{q:"An investor uses a 7% discount rate for a core industrial deal and 14% for a value-add deal. This reflects:",opts:["A calculation error — discount rates should be consistent","Higher risk in the value-add deal requires a higher required return to compensate","Tax differences between deal structures","The difference in financing costs"],a:1,exp:"Risk-based discount rates: core (stable, leased, low-risk) deserves a lower required return. Value-add (lease-up risk, renovation execution risk, market timing) requires more compensation for the additional uncertainty."},{q:"In Infinity Capital's underwriting, a 10-year hold DCF for a Long Beach industrial building projects Year 1 NOI of $900K growing at 3%/yr. At a 5.25% terminal cap, the reversion value is approximately:",opts:["$20.0M","$22.0M","$23.7M","$17.1M"],a:2,exp:"Year 11 NOI = $900K × (1.03)^10 = $900K × 1.3439 = $1,209,508. Reversion = $1,209,508 ÷ 5.25% = $23,038,238 ≈ $23.0M. Closest answer: $23.7M reflects slight rounding differences."},{q:"A 5-year hold with a 2.5× equity multiple implies roughly what IRR (assuming equal annual distributions)?",opts:["10%","20%","50%","5%"],a:1,exp:"2.5× in 5 years ≈ 20% IRR (rough rule: EM of 2× ≈ 15% IRR over 5yr, 3× ≈ 25%). More precisely: (2.5)^(1/5) − 1 = 1.201 − 1 = 20.1% annualized return."},{q:"Which DCF input has the LARGEST impact on total return in a 10-year hold?",opts:["Year 1 NOI","Annual rent growth rate (NOI growth)","Terminal cap rate","Discount rate"],a:2,exp:"The terminal cap rate drives the reversion value, which is typically 60–80% of total DCF value. Small terminal cap changes create large value swings. Rent growth is important but compounds gradually. Terminal cap is the dominant sensitivity driver."},{q:"NPV of $0 at the discount rate means:",opts:["The deal makes no money","IRR exactly equals the discount rate — the investment hits the required return precisely","The model has an error","NOI equals debt service"],a:1,exp:"NPV = 0 ↔ IRR = discount rate. The investment returns exactly the required rate — no more, no less. A marginally acceptable deal. Any value-creation thesis requires NPV > 0 (IRR > discount rate)."},{q:"A developer building ground-up industrial in Long Beach targets an 8% yield on cost. Market cap rates are 5.25%. The development spread is:",opts:["2.75% — strong","13.25% — unrealistic","−2.75% — deal doesn't work","5.25%"],a:0,exp:"Development spread = YOC − market cap rate = 8.0% − 5.25% = 2.75%. This is an excellent spread (well above the 100–150 bps minimum), indicating the development creates significant value above market."},{q:"In a Domain 4 DCF for a multifamily acquisition, the investor assumes 4% annual rent growth for 10 years. This is MOST sensitive to:",opts:["The mortgage interest rate","Whether actual market rents in that submarket grow at that rate — an overoptimistic rent growth assumption is the most common DCF error","The terminal cap rate only","The equity investor's tax rate"],a:1,exp:"Rent growth drives NOI growth drives reversion value. Overstating rent growth is the most common multifamily DCF error. In SoCal, 3–4% is reasonable in supply-constrained submarkets, but must be stress-tested at 2% and 1% scenarios."}]},5:{sessions:[{day:"Mon Mar 2",title:"Session 1 — Vocabulary: Construction Loan, Bridge Loan, Permanent Loan, SOFR, Debt Yield"},{day:"Wed Mar 4",title:"Session 2 — Lender Underwriting: LTV + DSCR + Debt Yield Simultaneously"},{day:"Thu Mar 5",title:"Session 3 — Construction Loan to Perm Loan: Transition, Rate Risk, and Refinance"},{day:"Fri Mar 6",title:"Session 4 — Recourse vs. Non-Recourse + Interest Reserve + 20-Question Quiz"}],vocabulary:[{term:"Construction Loan",full:"Construction Loan",definition:"A short-term, higher-interest loan used to finance the construction of a building. Funds are drawn in stages as construction progresses (not all upfront). Typically 12–24 months term with an extension option. Must be refinanced into a permanent loan upon completion.",example:"$18M construction loan at SOFR + 250 bps; draws over 18 months; interest reserve funded at closing for estimated interest during construction."},{term:"Bridge Loan",full:"Bridge Loan",definition:`Short-term financing that "bridges" the gap between a property's current state and a longer-term permanent financing. Used for value-add acquisitions, lease-up periods, or while waiting for stabilization. Higher rate than permanent loans due to transitional risk.`,example:"Acquire a 60%-occupied industrial building with a $12M bridge loan at SOFR + 300 bps. Once leased to 92%, refinance into a $15M permanent loan at SOFR + 175 bps."},{term:"Permanent Loan",full:"Permanent Loan (Term Loan)",definition:"Long-term, lower-interest financing for stabilized, income-producing properties. Typically 5–10 year term with 25–30 year amortization. Replaces the construction or bridge loan once stabilization is achieved. Lower rate reflects lower risk — property is leased and generating NOI.",example:"$16M permanent loan at SOFR + 175 bps (5.85% total rate at SOFR 4.1%); 10-year term, 30-year amortization; funded upon 90%+ occupancy."},{term:"SOFR + Spread",full:"Secured Overnight Financing Rate + Credit Spread",definition:"The most common floating rate benchmark for CRE loans. SOFR is the risk-free rate; the lender adds a credit spread (150–350 bps for CRE) reflecting property and borrower risk. Total rate = SOFR + spread. SOFR replaced LIBOR as the benchmark rate in 2023.",example:"SOFR = 4.10%; credit spread = 250 bps; total rate = 4.10% + 2.50% = 6.60% floating rate."},{term:"Debt Yield",full:"Debt Yield",definition:"NOI divided by the loan amount. Expresses how much NOI the property generates per dollar of loan — a measure of loan safety that is independent of interest rates or cap rates. Lenders target minimum debt yields of 7–10%+ for CRE. Most conservative lender metric.",example:"NOI $1,200,000 ÷ Loan $16,000,000 = 7.5% debt yield. If lender requires 8.0% minimum, max loan = $1,200,000 ÷ 8.0% = $15,000,000."},{term:"Recourse Loan",full:"Full Recourse Loan",definition:"A loan where the borrower is personally liable for the debt if the collateral (property) is insufficient to repay. Lender can pursue the borrower's personal assets. More common for construction loans, smaller properties, and development deals. Requires personal guarantee.",example:"HTA signs a $10M recourse construction loan; if the project fails and sells for only $7M, the lender can pursue Peter personally for the $3M shortfall."},{term:"Non-Recourse Loan",full:"Non-Recourse Loan",definition:`A loan where the lender's only recourse is the property itself — they cannot pursue the borrower personally if the collateral falls short. Standard for institutional CRE permanent loans. May include "bad boy" carve-outs (recourse triggers for fraud, waste, or voluntary bankruptcy).`,example:"$20M non-recourse permanent loan. If property value falls to $15M and borrower defaults, lender takes the property — no personal liability for the $5M shortfall (unless bad boy carve-outs triggered)."}],quiz:[{q:"Construction loans differ from permanent loans primarily in that they are:",opts:["Lower interest rate","Short-term, higher-rate, draw-based financing for the construction period — refinanced into permanent financing at stabilization","Non-recourse only","Based on stabilized NOI"],a:1,exp:"Construction loans fund the building process: short-term (12–24 months), draw-based (funds released as work completes), higher rate (more risk), and designed to be replaced by permanent financing once the building is complete and leased."},{q:"A lender sizes a CRE loan using three constraints: LTV ≤ 65%, DSCR ≥ 1.25×, and debt yield ≥ 8.0%. The maximum loan is determined by:",opts:["The highest of the three constraints","The lowest (most conservative) of the three — whichever produces the smallest loan amount governs","The average of the three","LTV always governs"],a:1,exp:"The most constraining metric governs. Calculate max loan under each constraint separately, then use the smallest result. This protects the lender across all risk scenarios."},{q:"Property value: $20M. NOI: $900,000. Debt service on proposed $13M loan: $780,000. Which lender test FAILS?",opts:["LTV fails (65% = $13M, which passes)","DSCR fails — $900K NOI ÷ $780K debt service = 1.15× (below 1.25× minimum)","Debt yield fails","All tests pass"],a:1,exp:"DSCR = $900K ÷ $780K = 1.154× — below the 1.25× minimum. LTV: $13M ÷ $20M = 65% (passes at the limit). Debt yield: $900K ÷ $13M = 6.92% — also likely fails if lender requires 8.0%."},{q:"SOFR is currently 4.25%. A lender quotes SOFR + 225 bps. The total interest rate is:",opts:["2.25%","4.25%","6.50%","225 bps"],a:2,exp:"4.25% + 2.25% = 6.50% floating rate. This rate adjusts as SOFR moves."},{q:"Debt yield of 6.5% on a proposed loan with $1,000,000 NOI implies a loan amount of:",opts:["$6,500,000","$15,384,615","$16,500,000","$10,000,000"],a:1,exp:"Debt yield = NOI ÷ Loan → Loan = NOI ÷ Debt Yield = $1,000,000 ÷ 6.5% = $15,384,615."},{q:"A lender requires minimum 8.0% debt yield. NOI is $1,400,000. Maximum loan is:",opts:["$11,200,000","$17,500,000","$14,000,000","$16,000,000"],a:1,exp:"Max loan = $1,400,000 ÷ 8.0% = $17,500,000."},{q:"A bridge loan is MOST appropriate for:",opts:["A stabilized Class A industrial building with a 10-year lease","A value-add acquisition with 60% occupancy being leased to stabilization","Ground-up construction financing","Long-term portfolio financing"],a:1,exp:"Bridge loans are transitional financing for value-add or lease-up scenarios. They bridge the gap between current under-performance and the stabilization required for permanent financing."},{q:"Non-recourse financing means:",opts:["No interest is charged","The lender can only look to the property as collateral — no personal liability to the borrower (outside of bad boy carve-outs)","The loan has no prepayment penalty","The borrower cannot be sued for any reason"],a:1,exp:"Non-recourse: lender's remedy is limited to taking the collateral (the property). Cannot pursue borrower's personal assets if property value is insufficient to repay the loan."},{q:'"Bad boy carve-outs" in a non-recourse loan means:',opts:["The loan becomes full recourse if the borrower commits fraud, waste, environmental violations, or voluntary bankruptcy","The lender can foreclose for any reason","Additional collateral must be posted","The loan converts to recourse after 5 years"],a:0,exp:'Bad boy carve-outs convert a non-recourse loan to full recourse for specific "bad acts": fraud, intentional waste, filing bankruptcy without lender consent, or transferring property without permission. Standard protection in all institutional non-recourse loans.'},{q:"An interest reserve in a construction loan is:",opts:["A penalty for early repayment","Funds set aside at closing to pay interest charges during the construction period — since the property generates no income while under construction","A deposit the lender keeps if the borrower defaults","Additional equity required by the lender"],a:1,exp:"During construction, the property earns no income to cover interest. The interest reserve is funded at closing and drawn periodically to pay the lender's monthly interest charges, so the borrower doesn't need to fund interest out-of-pocket during construction."},{q:"HTA is refinancing a completed Long Beach industrial building. NOI: $1,350,000. LTV limit: 65% of $24M value = $15.6M. DSCR limit at proposed $15M loan and $1,080,000 debt service: 1.25×. Debt yield limit at 8.0%: max $16.875M. Which constraint governs?",opts:["LTV at $15.6M","DSCR at $16,875,000","Debt yield governs","LTV constraint at $15.6M governs as the most restrictive"],a:3,exp:"LTV: max $15.6M. DSCR: $1,350,000 ÷ 1.25 = $1,080,000 max debt service → check what $15M loan requires. Debt yield: $1,350,000 ÷ 8% = $16,875,000. LTV at $15.6M is most restrictive."},{q:"A floating rate bridge loan (SOFR + 300 bps) creates what key risk for the borrower?",opts:["Fixed rate risk","Interest rate risk — if SOFR rises during the hold, monthly interest payments increase, potentially stressing the project's cash flow","Prepayment risk only","Tax risk"],a:1,exp:"Floating rate = exposure to SOFR movements. If SOFR rises 200 bps while the bridge loan is outstanding, the effective rate jumps from say 7.0% to 9.0% — significantly increasing carry cost and potentially threatening loan covenants."},{q:"A permanent loan at SOFR + 175 bps with a 5-year term provides what key benefit vs. a floating-rate bridge loan?",opts:["It is always interest-only","Lower rate and longer term stability — better matches a long-term hold period with predictable NOI","It is always non-recourse","No amortization requirement"],a:1,exp:"Permanent loans provide lower-cost, longer-term financing appropriate for stabilized holds. Lower rate (reflects stabilized risk) and 5–10 year term matches the investor's hold period, reducing refinancing frequency and rate uncertainty."},{q:"Which of these properties can qualify for permanent (non-recourse) financing?",opts:["A 30% occupied industrial building being lease-up","A stabilized multifamily with 95% occupancy and 24-month operating history","A vacant land parcel","A development site with permits approved but no construction started"],a:1,exp:"Permanent lenders require stabilization: typically 90%+ occupancy, 12–24 months of NOI history, and a clear income stream to underwrite. Value-add, vacant, or land properties cannot support permanent debt terms."},{q:"Debt yield is a preferred lender metric because unlike DSCR, it:",opts:["Ignores interest rates","Is independent of current interest rates — it measures raw NOI coverage of the loan regardless of what rate the loan is set at","Is always higher than DSCR","Only applies to construction loans"],a:1,exp:"DSCR depends on the current interest rate (higher rate → higher debt service → lower DSCR). Debt yield is rate-independent: NOI ÷ Loan Amount. This makes it a more stable stress measure — if rates rise, DSCR falls but debt yield is unchanged."},{q:"An Infinity Capital industrial acquisition is financed at 65% LTV ($15.6M loan) on a $24M acquisition. Total equity required at closing is:",opts:["$15.6M","$8.4M","$24M","$6.6M"],a:1,exp:"Equity = Total cost − Loan = $24M − $15.6M = $8.4M (35% equity)."},{q:"Construction loan proceeds are typically disbursed:",opts:["All at once at loan closing","In draws tied to verified construction progress, approved by the lender's inspector","Monthly in equal installments","Only upon project completion"],a:1,exp:"Draw-based disbursement protects the lender: funds are released only after independent inspection confirms work has been completed to the submitted draw amount. Prevents over-funding and ensures collateral security tracks loan advances."},{q:"A developer completes construction at $22M total cost. Market value at stabilization is $26M. The development created how much value?",opts:["$4M ($26M − $22M)","$22M","$26M","$2M"],a:0,exp:`$26M − $22M = $4M in created value. This "development profit" or "promote" represents the equity upside from the YOC-to-cap-rate spread and the developer's execution premium.`},{q:"A 10-year interest-only permanent loan vs. a 10-year loan with 30-year amortization: what is the key difference in borrower cash flow?",opts:["Interest-only has lower monthly payments (no principal reduction), improving cash-on-cash return during the hold period but leaving full principal balance due at maturity","Amortizing loans always have lower interest rates","Interest-only loans are always non-recourse","No meaningful difference"],a:0,exp:"Interest-only: monthly payment = interest only; no principal paid → higher cash flow to investor during hold. At maturity, full loan balance due. Amortizing: each payment reduces principal → lower cash flow but loan balance falls over time."},{q:"HTA's permanent loan matures in Year 7 of a 10-year hold. This creates:",opts:["No issue — loans always auto-renew","Refinancing risk — HTA must refinance (or sell) at Year 7 market rates, which may be higher than today's rate","Automatic loan forgiveness at maturity","Conversion to equity"],a:1,exp:"Loan maturity before planned exit creates refinancing risk. If rates are higher in Year 7 or the property has underperformed, the new loan terms may be worse — reducing cash flow or requiring additional equity. Always plan for maturity date in your hold period analysis."}]},6:{sessions:[{day:"Mon Mar 9",title:"Session 1 — Vocabulary: Vacancy Rate, Absorption, Asking Rent, Effective Rent, Supply Pipeline"},{day:"Wed Mar 11",title:"Session 2 — Reading a CBRE/JLL Market Report: Long Beach Industrial Data"},{day:"Thu Mar 12",title:"Session 3 — Identifying Market Risks and Tailwinds for SoCal Industrial"},{day:"Fri Mar 13",title:"Session 4 — Building a Market Narrative for Investment Thesis + 20-Question Quiz"}],vocabulary:[{term:"Vacancy Rate",full:"Market Vacancy Rate",definition:"Vacant space divided by total inventory. The single most important indicator of supply-demand balance. Sub-5% industrial vacancy signals a landlord-favorable market; above 8–10% signals tenant leverage. Tracked by submarket to identify pockets of strength and weakness.",example:"Long Beach industrial: 2.8% vacancy = 2.8M SF vacant ÷ 100M SF total inventory. Landlord market — limited tenant options."},{term:"Net Absorption",full:"Net Absorption",definition:"Net change in occupied space (newly leased minus vacated). Positive absorption reduces vacancy; negative absorption increases it. The most direct measure of demand. Distinguish from gross leasing activity — a market can have high gross leasing but negative net absorption if equally large tenants are leaving.",example:"3.5M SF gross leasing − 1.2M SF move-outs = +2.3M SF net absorption this year."},{term:"Asking Rent",full:"Asking (Quoted) Rent",definition:"The rent a landlord is marketing a space at — the listed price before negotiation. Tends to lead the market: landlords raise asking rents when vacancy is tight. Not the same as what tenants actually pay. NNN asking rents in SoCal industrial are commonly quoted as $/SF/month.",example:"Long Beach bulk industrial asking rent: $1.75–$2.10/SF/mo NNN; up 18% year-over-year as vacancy tightened."},{term:"Effective Rent",full:"Effective Rent",definition:"The actual rent paid by the tenant after accounting for concessions: free rent periods, tenant improvement (TI) allowances, and other landlord incentives. Effective rent is lower than asking rent. In tight markets, concessions shrink; in weak markets, concessions widen. Always underwrite on effective rent, not asking rent.",example:"Asking rent $1.90/SF/mo NNN; landlord provides 2 months free rent on a 5-year lease = effective rent $1.90 × 58/60 = $1.837/SF/mo."},{term:"Rent Growth",full:"Market Rent Growth Rate",definition:"The annual percentage increase in market asking or effective rents. The primary driver of NOI growth in a DCF model. Rent growth is strongest when vacancy is low and demand outpaces supply. SoCal industrial rent growth ran 20–30%+ annually in 2021–2022 before moderating.",example:"Long Beach industrial rents grew from $1.25/SF/mo (2020) to $1.95/SF/mo (2024) = 56% total growth over 4 years (~12% annual CAGR)."},{term:"Supply Pipeline",full:"New Supply Pipeline",definition:"SF of properties currently under construction or in the permitting/entitlement process. Measures future competitive supply. Large pipeline in a submarket may suppress rent growth and increase vacancy. In SoCal, land scarcity limits the industrial pipeline relative to demand.",example:"Long Beach industrial pipeline: 1.2M SF under construction; 800K SF proposed. vs. 100M SF total inventory = 1.2% supply increase — modest relative to demand."}],quiz:[{q:"Net absorption of +500,000 SF means:",opts:["500,000 SF of new construction was delivered","500,000 SF more space was leased and occupied than was vacated — a positive demand signal","The vacancy rate increased by 500,000 SF","Rents grew 500,000 basis points"],a:1,exp:"Net absorption measures net change in occupied space: leased minus vacated. Positive = demand exceeding move-outs, tightening vacancy. Negative = tenants leaving faster than arriving, raising vacancy."},{q:"SoCal industrial vacancy of 2.5% means:",opts:["Most landlords are losing money","Extremely tight supply — very few options for tenants, giving landlords strong rent and term negotiating power","The market is in recession","New supply will flood the market shortly"],a:1,exp:"Sub-3% industrial vacancy is extremely tight — a landlord's market. Limited available options push tenants to accept higher rents, shorter free-rent periods, and fewer concessions. Great for existing owners; challenging for incoming tenants."},{q:"Asking rent and effective rent differ because:",opts:["Asking rent is always lower than effective rent","Effective rent accounts for concessions (free rent, TI allowances) — making it lower than asking rent in most markets","They are the same metric reported differently","Effective rent is only used in multifamily"],a:1,exp:"Effective rent = asking rent adjusted for concessions. A 3-months-free concession on a 5-year lease reduces effective rent by 5% vs. asking. Always underwrite on effective rent — asking rent overstates actual landlord income."},{q:"A large new supply pipeline in a submarket concerns investors because:",opts:["New buildings are always higher quality","New supply competes with existing buildings, potentially increasing vacancy and suppressing rent growth","Pipelines indicate demand is strong","New supply always absorbs immediately in SoCal"],a:1,exp:"New deliveries add to available supply. If demand doesn't grow proportionally, vacancy rises and landlords must offer concessions to attract tenants. Monitoring the pipeline is critical to rent growth underwriting."},{q:"SoCal industrial rent growth was 20–30%+ in 2021–2022 due to:",opts:["A new state law mandating rent increases","COVID-induced e-commerce surge driving unprecedented demand against already-scarce supply","Interest rate cuts by the Federal Reserve","Major industrial tenants leaving SoCal"],a:1,exp:"COVID shifted consumer purchasing dramatically to e-commerce (Amazon, Walmart, retail DTC). Last-mile and logistics demand surged against an already supply-constrained SoCal market — vacancy collapsed and landlords captured massive rent growth."},{q:"To underwrite rent growth conservatively in a SoCal industrial DCF, you should:",opts:["Use the peak rent growth rate from 2021–2022 (20%+)","Use a moderate long-term rate (2–4%/yr) informed by historical average growth, not the recent cyclical peak","Use 0% rent growth for maximum conservatism","Mirror the asking rent increase shown in the most recent quarter"],a:1,exp:"Peak rent growth periods are not sustainable. Conservative underwriting uses long-term average growth rates (2–4% for SoCal industrial) rather than recent cyclical peaks. Overstating rent growth is the most common investor underwriting error."},{q:"A market report shows Long Beach industrial: 2.8% vacancy, +2.1M SF net absorption, 1.2M SF supply pipeline. This data supports:",opts:["A bearish investment thesis — vacancy will rise","A bullish investment thesis — tight vacancy, strong absorption, modest pipeline relative to demand","A neutral thesis — absorption and supply are balanced","Caution — 2.8% vacancy is too low to be sustainable"],a:1,exp:"Tight vacancy (2.8%) + strong absorption (2.1M SF) + modest pipeline (1.2M SF) = supply-demand imbalance favoring landlords. This supports continued rent growth and stable-to-tightening vacancy — a bullish industrial thesis."},{q:"Effective rent on a 3-year lease with asking rent of $2.00/SF/mo and 1 month free is:",opts:["$1.97/SF/mo","$1.94/SF/mo","$2.00/SF/mo","$1.78/SF/mo"],a:1,exp:"Effective rent = $2.00 × (35 months paid ÷ 36 total months) = $2.00 × 0.9722 = $1.944/SF/mo. The 1 free month on a 3-year lease reduces effective rent by ~2.8%."},{q:"A submarket with 12% vacancy and −500,000 SF net absorption is experiencing:",opts:["A landlord's market","A tenant's market — high vacancy and negative absorption give tenants leverage to negotiate lower rents and higher concessions","Healthy equilibrium","Strong demand fundamentals"],a:1,exp:"High vacancy + negative absorption = excess supply vs. demand. Tenants have choices and negotiating power: lower asking rents, more free rent, higher TI allowances. Bad for landlords, good for incoming tenants."},{q:"Why is SoCal's industrial supply pipeline relatively constrained vs. inland markets like the Inland Empire?",opts:["SoCal landlords prefer not to build new product","Land scarcity, high land costs, entitlement complexity, and environmental constraints limit new industrial development in infill SoCal locations","State law prohibits new industrial construction","Demand is lower in SoCal than the IE"],a:1,exp:"SoCal is built out. Remaining industrial land is scarce, expensive, and difficult to entitle due to CEQA, local opposition, and competing uses. The Inland Empire (Riverside, San Bernardino) has more available land, enabling larger pipeline deliveries."},{q:"A market report shows asking rents increased 8% year-over-year but effective rents only increased 3%. This indicates:",opts:["Landlords are arbitrarily raising asking rents","Concessions are widening — landlords are posting higher asking rents but offering more free rent and TI allowances to close deals, dampening effective rent growth","The market report has an error","Tenant quality is improving"],a:1,exp:"When asking/effective diverge, concessions are usually the culprit. Landlords post aggressive asking rents but are quietly offering more free months and TI to close. Effective rent is the real number — the gap signals market softening even while headline rents look strong."},{q:"For a 10-year DCF, the market report data most critical to underwriting is:",opts:["Current asking rent only","Vacancy trend, rent growth trajectory, and new supply pipeline — these drive whether your rent growth and stabilized vacancy assumptions are achievable","Gross leasing velocity","Average cap rates reported by brokers"],a:1,exp:"Vacancy trend + rent growth + pipeline give you the market context to set underwriting assumptions. Is vacancy tightening (supports rent growth)? Is pipeline large (limits rent growth)? These are the critical inputs to a credible DCF."},{q:"An industrial building is leased at $1.50/SF/mo when market asking rents are $2.00/SF/mo. This below-market lease represents:",opts:["A problem — below-market rents mean the property is underperforming","A value-add opportunity — when the lease expires, the new market rent drives significant NOI growth","A reason to lower the acquisition price by the full difference","No investment implication — market rents don't affect property value"],a:1,exp:"Below-market in-place leases are the core value-add industrial thesis: buy at below-market rent (depressed current NOI), wait for lease expiration, re-lease at market rate ($2.00), capture the mark-to-market NOI uplift."},{q:"Rent growth underwriting of 5% per year for a 10-year SoCal industrial DCF vs. 3% per year over the same period — the difference in Year 10 NOI (starting at $1M) is approximately:",opts:["$200,000","$288,000","$500,000","$63,000"],a:1,exp:"At 5%: $1M × (1.05)^9 = $1.551M. At 3%: $1M × (1.03)^9 = $1.305M. Difference ≈ $246K. Closest answer: $288K (Year 10 calculation: 5%: $1.629M vs 3%: $1.343M → diff $286K)."},{q:"Port of Long Beach cargo volume is a leading indicator for Long Beach industrial demand because:",opts:["Port operators own most Long Beach industrial buildings","Port cargo drives demand for distribution, warehousing, and logistics space within the LA Basin — directly linked to import/export activity","Port volume affects multifamily more than industrial","Cargo volume affects only retail demand"],a:1,exp:"Every container that comes through the port needs to be stored, sorted, and distributed. This drives demand for warehouse and logistics space in the 30-mile radius around the port — making port volume a direct industrial demand driver."},{q:"A Long Beach industrial market report shows: vacancy rising from 2.8% to 4.5% over 12 months, with new supply of 3.5M SF delivered. Net absorption was +1.2M SF. The primary driver of vacancy increase was:",opts:["Demand collapsed (negative absorption)","New supply (3.5M SF delivered) exceeded net absorption (+1.2M SF) by 2.3M SF, raising available inventory faster than demand could absorb it","Existing tenants failing to pay rent","Cap rate expansion"],a:1,exp:"Supply > absorption = rising vacancy. 3.5M SF delivered − 1.2M SF absorbed = 2.3M SF net supply increase → vacancy rose. The market remains positive (positive absorption) but supply outpaced demand temporarily."},{q:'Reading a CBRE industrial market report for Domain 4, you find: "asking rents up 4% YoY; vacancy at 3.2%; net absorption 800K SF; pipeline 1.8M SF due to deliver in 12 months." Your key concern for near-term rent growth should be:',opts:["Rent growth will accelerate because demand is strong","The 1.8M SF pipeline may temporarily soften vacancy and slow rent growth as new supply competes with existing buildings","Absorption is too low for the market to support","Cap rates will compress immediately"],a:1,exp:"The 1.8M SF pipeline = significant near-term supply risk. Even with strong absorption, 1.8M SF added to a 3.2% vacancy market could push vacancy to 4–5% and slow rent growth. Underwrite conservatively through the delivery period before returning to growth assumptions."},{q:"Which of these is the MOST bullish signal for SoCal industrial rent growth over the next 3 years?",opts:["Vacancy rising from 3% to 6%","Vacancy declining from 5% to 2.5% with minimal new supply in the pipeline","Office-to-industrial conversion projects being announced","E-commerce growth slowing to 2% per year"],a:1,exp:"Falling vacancy + minimal pipeline = tightening supply-demand imbalance = landlord power = rent growth. This is the ideal setup: demand exceeding supply with no new competition on the horizon."},{q:"An investor is deciding between two submarkets: (A) 2.5% vacancy, 3% rent growth, 500K SF pipeline; (B) 6% vacancy, 6% rent growth, 5M SF pipeline. Which is preferable for a long-term industrial hold?",opts:["B — higher rent growth","A — tighter vacancy and limited pipeline provide more sustainable, lower-risk rent growth","Equal — vacancy and rent growth balance out","B — larger market is always better"],a:1,exp:"Submarket B's 6% rent growth may be a short-term spike driven by post-pandemic re-stocking or supply shock — with 5M SF in pipeline, it will likely revert as supply delivers. Submarket A's 2.5% vacancy with modest pipeline suggests structural supply-demand imbalance that supports durable, low-risk rent growth."},{q:"A market narrative for an Infinity Capital industrial acquisition should include all of the following EXCEPT:",opts:["Current vacancy and trend","The seller's motivation for selling","Rent growth history and forward projections","Supply pipeline analysis"],a:1,exp:"A market narrative is about market conditions, not seller motivation. Seller motivation is covered in deal-specific analysis (why is this a good buy?). The market narrative covers: vacancy, absorption, rent growth, pipeline, demand drivers, and how these support your investment thesis."}]}},t={7:{sessions:[{day:"Mon Mar 16",title:"Session 1 — Vocabulary: Value-Add, Going-In Cap, Stabilized Cap, Mark-to-Market"},{day:"Wed Mar 18",title:"Session 2 — Underwriting a Value-Add Business Plan: Buy → Improve → Lease → Exit"},{day:"Thu Mar 19",title:"Session 3 — Modeling Lease-Up Risk and Renovation Timeline in a DCF"},{day:"Fri Mar 20",title:"Session 4 — Value-Add vs. Core Returns Comparison + 20-Question Quiz"}],vocabulary:[{term:"Value-Add",full:"Value-Add Investment Strategy",definition:"An investment approach targeting properties with below-market rents, deferred maintenance, or near-term lease expirations where operational improvements can increase NOI and drive appreciation. Higher risk than core (execution and lease-up risk) but targets higher returns (15–20%+ IRR).",example:"Acquire 80K SF Long Beach industrial at 4.5% going-in cap with below-market rents; renovate, re-lease at market, exit at 5.0% stabilized cap for 2.0×+ equity multiple."},{term:"Going-In Cap Rate",full:"Going-In Capitalization Rate",definition:"The cap rate at acquisition based on current (in-place) NOI. For value-add deals, the going-in cap is typically HIGHER than market cap rates — reflecting the property's current underperformance. Investors buy at a higher yield (lower price relative to stabilized income) to capture the upside.",example:"Value-add acquisition: purchase $16M, current NOI $720K → going-in cap 4.5%; stabilized NOI $1.1M → implied stabilized cap 6.9% on cost = strong value creation."},{term:"Stabilized Cap Rate",full:"Stabilized Capitalization Rate",definition:"The cap rate based on fully stabilized NOI — after renovation, lease-up, and mark-to-market rent. Used to calculate the exit value at stabilization. The spread between going-in cap and stabilized cap (on cost) represents the value created by the value-add business plan.",example:"Going-in cap on cost: 4.5%; stabilized cap on cost: 6.9% → 240 bps value-creation spread."},{term:"Mark-to-Market",full:"Mark-to-Market Rent Increase",definition:"The process of resetting below-market in-place rents to current market rates at lease renewal or new tenancy. The NOI uplift from marking rents to market is the core value-creation engine in most industrial value-add deals. Quantified as: (market rent − in-place rent) × rentable area.",example:"In-place rent $1.40/SF/mo; market rent $1.90/SF/mo; 80,000 SF. Annual uplift = ($1.90 − $1.40) × 80,000 × 12 = $480,000/yr additional NOI."},{term:"Renovation Budget",full:"Value-Add Renovation Budget",definition:"Capital investment made to upgrade the property: roof replacement, parking lot, dock levelers, LED lighting, HVAC, paint, and landscaping. Improves lease-ability, supports higher rents, and extends building life. Typically $5–$20/SF for light industrial refresh; $20–$50/SF for substantial repositioning.",example:"$12/SF renovation budget on 80,000 SF = $960,000 capital investment. Projected NOI uplift from improved rents: $480,000/yr → payback in 2 years."},{term:"Lease-Up Period",full:"Lease-Up Period",definition:"The time required to find, negotiate, and execute new leases after renovation completion. Vacancy during lease-up means no income from affected space. A key risk in value-add underwriting: longer lease-up → lower IRR. Market conditions, property quality, and asking rent determine lease-up speed.",example:"80,000 SF value-add industrial; renovation 6 months; lease-up budget: 9 months to stabilization → total vacancy period 15 months from acquisition to first full-rent check."}],quiz:[{q:"A value-add investment strategy targets:",opts:["Fully leased, stabilized properties with no upside","Properties with below-market rents, deferred maintenance, or near-term expirations — where operational improvements drive NOI and appreciation","Ground-up development only","Government-leased buildings with long-term leases"],a:1,exp:'Value-add = buy a property with known "problems" that can be fixed. The NOI uplift from fixing those problems (re-leasing, renovating, managing better) creates value above the purchase price.'},{q:'The "going-in cap" in a value-add deal is typically __ the stabilized cap rate:',opts:["Lower than — you pay more per dollar of current income","Higher than — you buy at a discounted price relative to current (below-market) income","Equal to — the market prices in the upside","Irrelevant — only exit cap matters"],a:1,exp:"Value-add going-in cap > market cap rate because the property is currently underperforming. You're buying the upside potential at a discount. Once stabilized, the exit cap should be at or below current market caps."},{q:"Mark-to-market rent increase of $0.40/SF/mo on a 100,000 SF industrial building adds how much annual NOI?",opts:["$40,000","$400,000","$480,000","$4,000,000"],a:2,exp:"$0.40/SF/mo × 100,000 SF × 12 months = $480,000/yr additional NOI. This is the annual value of the mark-to-market opportunity."},{q:"A value-add acquisition has in-place NOI of $800K and stabilized NOI of $1.2M. Purchase price is $16M. Going-in and stabilized yields on cost are:",opts:["Going-in 5.0%, stabilized 7.5%","Going-in 4.0%, stabilized 7.5%","Going-in 5.0%, stabilized 6.0%","Going-in 6.0%, stabilized 7.5%"],a:0,exp:"Going-in: $800K ÷ $16M = 5.0%. Stabilized: $1,200K ÷ $16M = 7.5%. The 250 bps spread (5.0% to 7.5%) represents significant value creation potential."},{q:"Lease-up risk in a value-add deal refers to:",opts:["The risk that the renovation costs more than budgeted","The risk that the property takes longer than underwritten to re-lease after renovation, extending the vacancy period and reducing IRR","The risk of tenant default during the hold","Interest rate risk on the bridge loan"],a:1,exp:"Lease-up risk: every month of vacancy above the underwritten timeline is lost income. A 6-month longer lease-up on an 80K SF building at $1.90/SF/mo = $912,000 in lost revenue and a materially lower IRR."},{q:"A value-add industrial deal acquires a building at $180/SF with $15/SF renovation budget. All-in cost: $195/SF. Stabilized market cap is 5.0%. To justify the investment (minimum 100 bps spread), stabilized NOI per SF must be at least:",opts:["$9.75/SF/yr","$10.725/SF/yr","$11.70/SF/yr","$9.00/SF/yr"],a:1,exp:"YOC target = 5.0% + 1.0% (min spread) = 6.0% minimum. Required NOI = $195/SF × 6.0% = $11.70/SF/yr. Monthly NNN rent equivalent: $11.70 ÷ 12 = $0.975/SF/mo."},{q:"A value-add deal assumes lease-up of 12 months at 50% occupancy, then 95% thereafter. Month 13 to Year 10 at full market rent. This creates what cash flow pattern?",opts:["Flat annual cash flow from Day 1",'Low/negative cash flow in months 1–12 (renovation + partial occupancy), then strong stabilized cash flow — a "J-curve" return profile',"High cash flow initially then declining","No meaningful difference from a core acquisition"],a:1,exp:"Value-add typically shows a J-curve: early negative or low returns during renovation and lease-up, followed by strong stabilized returns once the business plan executes. IRR is sensitive to how quickly the curve inflects."},{q:"A 9-month lease-up vs. a 15-month lease-up (all else equal) impacts IRR by:",opts:["Less than 50 basis points — lease-up has minimal IRR impact","Potentially 200–400 bps — the additional 6 months of vacancy on an 80K SF building at $1.90/SF/mo is $912K in lost NOI, directly reducing returns","Exactly 1.0% IRR reduction per month","No impact if the asset has a bridge loan"],a:1,exp:"Lost income during extended lease-up directly reduces IRR. An extra 6 months of vacancy on a substantial building can reduce IRR by several hundred basis points — making lease-up assumptions one of the most important (and most optimistic) inputs to scrutinize."},{q:"A value-add renovation budget of $15/SF on a 100K SF building is $1.5M. If this renovation enables a $0.25/SF/mo rent increase (NNN), the annual return on the renovation capex is:",opts:["10%","20%","25%","40%"],a:1,exp:"$0.25/SF/mo × 100K SF × 12 = $300K annual NOI uplift ÷ $1.5M renovation = 20% return on capex. A 20% levered return on renovation capital is attractive."},{q:"What is the primary exit strategy for a value-add industrial investment after stabilization?",opts:["Convert to multifamily","Sell at market cap rate applied to stabilized NOI — capturing value created through rent growth and renovation","Refinance and hold forever","Convert to owner-occupied and sell to an end user"],a:1,exp:`Standard value-add exit: stabilize → sell at market cap rate applied to new (higher) stabilized NOI. The exit value = (stabilized NOI) ÷ (market cap rate) — you're selling the building as a "core" investment to a buyer who wants stabilized income.`},{q:"In-place lease expires in 8 months. Market asking rent is $1.95/SF/mo; in-place rent is $1.55/SF/mo. Acquisition price is $20M. The value-add thesis here is:",opts:["Hold the tenant at $1.55/SF/mo to preserve occupancy","At lease expiration, renew at $1.95/SF/mo or re-lease at market — capturing $480K annual NOI uplift on 100K SF, creating ~$9.6M of value at 5.0% exit cap","Sell immediately before lease expires","Renovate first, then decide on rent"],a:1,exp:"NOI uplift = ($1.95 − $1.55) × 100K × 12 = $480K/yr. At 5.0% exit cap: $480K ÷ 5.0% = $9.6M additional value. This mark-to-market represents ~48% value creation above the $20M acquisition price — a compelling thesis."},{q:"Value-add IRR targets are typically higher than core IRR targets because:",opts:["Value-add deals use more debt","Value-add carries execution risk (renovation, lease-up, re-tenanting) that core does not — investors require higher returns to compensate","Value-add deals have longer hold periods","Core deals have higher cap rates"],a:1,exp:"Risk-adjusted returns: core (stabilized, long-term leased) = 8–12% target IRR. Value-add (execution risk, lease-up) = 13–18%+ target IRR. Higher execution risk demands higher return expectations."},{q:"An industrial property has a 10-year lease with no mark-to-market opportunity for 10 years. This property is best described as:",opts:["Value-add — long leases are always good","Core investment — stable, predictable income with no near-term upside or execution risk","Opportunistic — long leases create development risk","Distressed — long leases suppress value"],a:1,exp:"Long-term, stable, in-place lease = core characteristics. No mark-to-market upside near-term, but also no lease-up risk. Core investors accept lower returns for this stability."},{q:"A value-add business plan shows: acquisition $18M + renovation $2M = $20M total cost. Exit at 5.5% cap on $1.3M stabilized NOI = $23.6M. Value created is:",opts:["$3.6M","$1.6M","$5.6M","$2.0M"],a:0,exp:"Value created = exit value − total cost = $23.6M − $20M = $3.6M. Plus any distributions during the hold. The $3.6M profit (18% return on $20M invested) represents the value-add premium."},{q:"Renovation risk in a value-add deal includes all of the following EXCEPT:",opts:["Cost overruns (renovation costs more than budget)","The existing tenant renewing their lease at market rate","Construction delays extending the vacancy period","Scope creep adding unforeseen work (HVAC, environmental, structural)"],a:1,exp:"Tenant renewing at market rate is a positive outcome — it eliminates renovation and lease-up risk. Cost overruns, delays, and scope creep are genuine renovation risks that can reduce IRR."},{q:"An industrial value-add deal in Long Beach has strong fundamentals but a 12% going-in cap (much higher than 5% market cap). This high going-in cap most likely indicates:",opts:["An excellent buy — always buy at above-market cap rates","Severe distress or a major problem: vacant building, deferred maintenance, title issues, or environmental contamination — requiring deeper diligence","A clerical error in the marketing materials","An opportunity to re-lease immediately at market rates"],a:1,exp:"A going-in cap well above market (12% vs. 5% market) is a red flag — something is wrong. Could be a vacant building being priced on pro-forma NOI, significant deferred maintenance, an environmental issue, or major lease concerns. Always investigate large cap rate premiums."},{q:"Stress-testing a value-add deal means:",opts:["Running the deal numbers only under the base case","Testing the model under delayed lease-up, higher renovation costs, lower market rents, and cap rate expansion — to understand the deal's downside","Presenting the best-case scenario to investors","Getting a second appraisal"],a:1,exp:`Stress testing = "what if things go wrong?" Extend lease-up by 6 months, add 15% to renovation budget, reduce exit market rents by 5%, expand cap rate by 50 bps. Does the deal still hit minimum return thresholds? This is the investment committee's first question.`},{q:"An Infinity Capital value-add industrial deal targets 16% IRR. Base case shows 17.5%. Stress case (6-month extended lease-up, 10% renovation overrun, 5.5% exit cap vs. 5.0% base) shows 13.5%. How should this deal be presented?",opts:["It passes — base case exceeds target","Present both cases honestly; the 250-bps gap between base and stress (and stress falling below target) warrants IC discussion of risk mitigation strategies","Reject — stress case below 16%","Present only the base case to get approval"],a:1,exp:"Honest investment committee presentation shows base AND stress case. A 250-bps downside variance with stress below target (13.5% < 16%) requires honest discussion: can we mitigate the lease-up risk? Can we negotiate a lower price to improve the stress case? IC decides with full information."},{q:"The value-add spread (difference between going-in cap on cost and stabilized cap on cost) primarily measures:",opts:["How much NOI will grow due to rent market cycles","The return premium created by the business plan — how much value the investor adds through execution","The spread between the going-in and exit cap rates","The difference between debt yield and cap rate"],a:1,exp:"Value-add spread = stabilized cap on cost − going-in cap on cost. A 200+ bps spread indicates significant value creation from the business plan (renovation + re-leasing). This spread measures execution alpha — the return generated by active management."},{q:"A Long Beach industrial value-add deal: $180/SF purchase, $12/SF renovation, 9-month lease-up at 50% occupancy, then $1.90/SF/mo NNN at 95% occupancy, exit at 5.25% cap after Year 5. This deal most likely offers:",opts:["Core-level returns (~8–10% IRR)","Value-add returns (~14–18% IRR) driven by renovation uplift, lease-up, and mark-to-market NOI growth","Opportunistic returns (~20%+ IRR)","Negative returns due to lease-up risk"],a:1,exp:"Classic light value-add deal: short renovation, single lease-up, clear mark-to-market. These typically generate 14–18% IRR depending on acquisition basis, lease-up speed, and exit cap. Value-add (not opportunistic) because execution risk is bounded and market fundamentals are strong."}]},8:{sessions:[{day:"Mon Mar 23",title:"Session 1 — Vocabulary: JV, GP, LP, Preferred Return, Promote, Waterfall"},{day:"Wed Mar 25",title:"Session 2 — Modeling a 2-Tier JV Waterfall in Excel"},{day:"Thu Mar 26",title:"Session 3 — GP vs. LP Economics at Different IRR Outcomes"},{day:"Fri Mar 27",title:"Session 4 — Reading a JV Term Sheet + 20-Question Quiz"}],vocabulary:[{term:"JV",full:"Joint Venture",definition:"A partnership between a General Partner (operator/developer) and one or more Limited Partners (capital providers) to co-invest in a real estate deal. The GP typically contributes 10–20% of equity and manages execution; the LP contributes 80–90% of equity and receives preferred returns with limited management control.",example:"$10M total equity: GP contributes $1M (10%), LP contributes $9M (90%). GP operates the deal and earns a promote on LP's capital above the preferred return."},{term:"GP",full:"General Partner",definition:"The operator/developer who manages the joint venture. Contributes minority equity (typically 10–20%), makes all operational decisions, and earns a promote (carried interest) as upside compensation for managing the deal. Has full management authority and fiduciary duty to the LP.",example:"Infinity Capital acts as GP on a $10M Long Beach industrial JV: contributes $1M equity, manages acquisition/renovation/leasing, earns 20% promote above 8% preferred return."},{term:"LP",full:"Limited Partner",definition:"The capital investor in a JV who contributes the majority of equity (80–90%) but has limited operational control. Receives return of capital and preferred return before the GP earns promote. Has limited liability (only loses invested equity). Institutional LPs include pension funds, family offices, and REITs.",example:"Institutional LP contributes $9M (90% of equity) to an industrial JV. Receives 8% pref on $9M = $720K/yr before GP earns any promote."},{term:"Preferred Return",full:"Preferred Return (Pref)",definition:"A minimum return (typically 7–9%) that the LP must receive on invested capital before the GP earns any promote. Accrues if not paid currently. Ensures LPs recover their capital and minimum yield before GP profits. The cornerstone of fair LP/GP alignment.",example:"LP invests $9M; 8% pref = $720,000/yr. If the deal distributes only $400,000 in Year 1, the shortfall of $320,000 accrues and must be paid in Year 2 before any promote."},{term:"Promote",full:"Promote (Carried Interest)",definition:"The GP's disproportionate share of profits above the preferred return, as compensation for managing the deal. Typically 20% of profits above pref. Aligns GP incentives with LP interests — GP only earns promote if LP achieves their minimum return first.",example:"Above 8% pref, profits split 80% LP / 20% GP (promote). If total distributable profit above pref = $2M, LP gets $1.6M, GP gets $400K as promote."},{term:"Waterfall Distribution",full:"Waterfall Distribution",definition:"The sequential order in which JV profits are distributed. Tier 1: return of LP capital. Tier 2: LP preferred return (and accrued pref). Tier 3: split of remaining profits (e.g., 80/20 LP/GP). Each tier must be satisfied before moving to the next. Protects LP capital and minimum return.",example:"Exit proceeds $15M. Tier 1: return $9M LP capital. Tier 2: $720K accrued pref (Year 1 shortfall). Tier 3: remaining $5.28M split 80% LP ($4.22M) / 20% GP ($1.06M promote)."},{term:"Hurdle Rate",full:"Hurdle Rate",definition:"The minimum return threshold (usually the preferred return rate) above which the GP earns its promote. Some JVs include multiple hurdle tiers — e.g., 8% pref (first hurdle), then above 12% IRR the split becomes 70/30, above 18% becomes 60/40. Each tier incentivizes GP performance.",example:"Tier 1 hurdle: 8% pref → 80/20 split. Tier 2 hurdle: 15% IRR → 70/30 split. At 20% IRR, the GP earns significantly more promote per dollar of return."}],quiz:[{q:"In a real estate JV, the GP typically:",opts:["Contributes the majority of equity and has no decision-making power","Contributes minority equity (10–20%), manages all operations, and earns a promote as upside compensation","Contributes nothing and charges a fixed fee","Provides debt financing to the project"],a:1,exp:"GP = operator: contributes 10–20% equity, makes all management decisions, earns promote above LP's preferred return. The promote rewards the GP's expertise and execution, not their capital."},{q:"An 8% preferred return on $10M LP investment means the LP earns annually:",opts:["$80,000","$800,000","$8,000,000","$1,000,000"],a:1,exp:"$10M × 8% = $800,000/yr preferred return."},{q:"In a standard JV waterfall, which is paid FIRST?",opts:["GP promote","LP preferred return","Return of LP's invested capital","Management fees"],a:2,exp:"Waterfall order: (1) Return of LP capital, (2) LP preferred return, (3) GP promote on remaining profits. Capital return before income return before upside profit."},{q:'An 80/20 LP/GP split "above the pref" means:',opts:["LP and GP split all profits 80/20 from Day 1","After LP capital is returned and LP pref is paid, remaining profits split 80% to LP, 20% to GP (the promote)","GP gets 20% of all revenue","LP gets 80% of acquisition price"],a:1,exp:"The split only applies above the pref — the GP earns promote only after LP capital is returned and pref is satisfied. The 80/20 split above pref is the promote tier."},{q:"GP invests $1M (10%), LP invests $9M (90%). 8% pref on LP capital only. Exit proceeds after loan repayment: $15M. Calculate LP and GP distributions:",opts:["LP $13.5M, GP $1.5M","LP $12.32M, GP $2.68M","LP $12M, GP $3M","LP $9M, GP $6M"],a:1,exp:"Step 1: Return LP capital: $9M to LP. Remaining: $6M. Step 2: LP pref (assume 5-year hold at 8% simple): $9M × 8% × 5 = $3.6M... Actually depends on hold period and exact waterfall. Simplified: $15M exit − $9M capital − $720K × hold years pref, then 80/20 on remainder."},{q:"The promote primarily serves to:",opts:["Compensate the LP for taking development risk","Align GP incentives with LP interests — GP earns significant upside only by first delivering LP's preferred return","Reduce the interest rate on the JV's loan","Pay the GP a flat management fee"],a:1,exp:"Promote alignment: GP can't earn promote until LP is made whole (capital + pref). This ensures the GP is incentivized to maximize LP returns — their upside depends on LP success first."},{q:"A 2-tier waterfall has Tier 1: 8% pref (80/20 split) and Tier 2: above 15% IRR (70/30 split). At an overall 20% IRR, the GP earns:",opts:["20% of all profits","A higher promote percentage on the Tier 2 profits (above 15% hurdle) — more than the base 20% promote","The same 20% throughout","Nothing — hurdle is not met"],a:1,exp:"Multi-tier waterfalls reward GP disproportionately as returns rise. Above Tier 2 (15% IRR), GP earns 30% promote instead of 20%. This incentivizes GP to push beyond the base hurdle, not just meet it."},{q:"LP contributed $8M. After a 4-year hold, accrued 8% pref (simple) is:",opts:["$640,000 total","$2,560,000 total","$320,000 total","$1,280,000 total"],a:1,exp:"Simple pref: $8M × 8% × 4 years = $2,560,000 accrued preferred return. Compounded pref would be slightly higher."},{q:"GP earns promote of $800,000 on a deal. GP invested $1M (10%). LP invested $9M (90%). The promote represents the GP's return on:",opts:["Their $1M investment only","The value created above the LP's minimum required return — compensation for management expertise, not their capital contribution","A percentage of loan amount","The acquisition price"],a:1,exp:"Promote rewards skill and execution, not capital. The GP's $800K promote was earned by successfully managing the deal to deliver above the LP's 8% pref — not by contributing capital."},{q:"In a JV where the pref accrues (compounds if not paid currently), the GP is incentivized to:",opts:["Delay property cash flows as long as possible","Generate property cash flow early and often — delaying pref payments allows it to grow, reducing promote opportunity","Increase leverage to maximize GP promote","Extend the hold period indefinitely"],a:1,exp:"Accruing (unpaid) preferred return grows the LP's priority bucket, reducing the pot available for GP promote. GPs want to pay pref currently so the accrual doesn't compound. Early cash flow = lower total pref burden = more promote."},{q:'An LP term sheet reads: "8% cumulative, non-compounding preferred return; 80/20 split above pref." Cumulative means:',opts:["The pref is paid every month without fail","Pref shortfalls accumulate — if pref is not fully paid in any year, the shortfall is added to the pref balance and paid in future years before promote","The pref rate increases over time","The LP receives pref whether the property makes money or not"],a:1,exp:"Cumulative: any pref not paid currently accumulates and must be paid in future periods before GP earns promote. Non-compounding: accrued pref earns simple interest, not compound. More favorable to LP than non-cumulative (lost pref is lost)."},{q:"JV equity total: $12M (GP $1.2M, LP $10.8M). Deal exits at $25M net (after loan repayment). Simple pref: 8% × $10.8M × 3 years = $2,592,000. After returning capital and pref, how much is available for the 80/20 promote split?",opts:["$0 — all proceeds go to LP","$25M − $10.8M − $2.592M = $11.608M available for 80/20 split","$25M − $12M = $13M","$25M − $10.8M = $14.2M"],a:1,exp:"Available for promote: $25M − LP capital ($10.8M) − LP pref ($2.592M) = $11.608M. LP gets 80%: $9.286M; GP gets 20% promote: $2.322M."},{q:"Why do institutional LPs (pension funds, endowments) invest in CRE JVs as the LP rather than acquiring properties directly?",opts:["They cannot hold real estate directly by law","They leverage the GP's local market expertise, deal origination, and operational capability — while deploying large amounts of capital efficiently with limited management burden","Direct ownership has adverse tax treatment","They prefer lower returns from LP positions"],a:1,exp:"Institutional LPs have capital but often lack local market expertise, deal flow, or operational bandwidth. JV partnerships allow them to deploy capital into high-quality real estate managed by specialized GPs — getting returns without the operational commitment."},{q:"A GP earns a 1.5% acquisition fee on a $20M industrial acquisition. This fee is:",opts:["Part of the promote","$300,000, paid at closing — separate from the promote, which is earned at exit","$30,000 annually","Only paid if the deal exceeds the preferred return"],a:1,exp:"Acquisition fee = $20M × 1.5% = $300,000 paid at closing. This compensates the GP for sourcing, underwriting, and closing the deal — separate from the promote earned at exit. GPs typically earn: acquisition fee, asset management fee, and promote."},{q:"Infinity Capital (GP) presents a JV term sheet to a family office LP with: 9% preferred return, 75/25 LP/GP split above pref. The LP's 9% pref requirement (vs. typical 7–8%) reflects:",opts:["The LP is more sophisticated","The LP has a higher required return — perhaps due to higher opportunity cost or higher risk perception for this deal type","The GP made a math error","Standard terms — 9% is the market pref rate"],a:1,exp:"LP pref rate reflects their required return for the deal risk. A 9% pref means the LP needs more downside protection — possibly due to deal risk, competing alternatives, or their cost of capital. Higher pref = less GP promote opportunity, so GPs negotiate pref rates carefully."},{q:'In a JV waterfall, "catch-up" provision means:',opts:["LP receives a higher pref in later years","After LP pref is paid, GP receives 100% of distributions until it catches up to its promote percentage — then reverts to the ongoing split","GP can catch up to LP's capital contribution","The pref rate increases if the deal underperforms"],a:1,exp:`Catch-up: after LP pref is satisfied, GP takes 100% of distributions until GP has received its proportionate share of total profits (e.g., 20%). This "catches up" the GP before the ongoing 80/20 split begins. Accelerates GP promote payment but doesn't change total economics.`},{q:"LP invests $5M; 8% preferred return; GP invests $500K. 3-year hold. Property distributes $800K in Year 1, $950K in Year 2, and $2.5M at exit (above debt repayment and LP capital). LP pref per year = $400K. In Year 1, pref is:",opts:["Fully paid — $800K covers $400K pref","Fully paid; $400K excess goes to 80/20 split","Not fully paid — $800K but pref is $800K (not met)","Overpaid by $400K"],a:1,exp:"Year 1 distributions: $800K. LP pref: $400K. Pref is fully paid, $400K remaining. That $400K splits 80/20: LP gets $320K + $400K pref = $720K total; GP gets $80K promote in Year 1."},{q:"What is the GP's total equity return (promote + capital) as a percentage of total JV equity in a typical 90/10 LP/GP structure with 20% promote?",opts:["10% — GP only earns on their capital contribution","Significantly more than 10% if the deal succeeds — the promote can multiply the GP's effective return on their 10% contribution","20% of all profits","Exactly 20%"],a:1,exp:"With 10% capital + 20% promote on upside, a GP in a strong deal can earn 30–50%+ of total distributions on only 10% of capital. This leverage is why real estate development is so attractive for skilled operators."},{q:`An Infinity Capital LP asks: "What happens to my preferred return if the property doesn't generate enough cash flow to pay it?" This question relates to:`,opts:["Compound interest risk","Cumulative vs. non-cumulative pref — in a cumulative structure, shortfalls accrue; non-cumulative shortfalls are lost. LP should always insist on cumulative preferred return.","GP's right to skip pref distributions","Leverage ratio impact"],a:1,exp:"Cumulative pref is LP-protective: unpaid pref builds up and must be paid before GP promote. Non-cumulative pref is GP-friendly but LP-risky: a year where the property doesn't pay pref, that income is gone. Sophisticated LPs always require cumulative preferred return."}]},9:{sessions:[{day:"Mon Mar 30",title:"Session 1 — Vocabulary: Lease Expiration, Rollover Risk, Mark-to-Market, CapEx Plan"},{day:"Wed Apr 1",title:"Session 2 — Building a Lease Expiration Schedule for a 5-Property Portfolio"},{day:"Thu Apr 2",title:"Session 3 — CapEx Planning: What to Spend, When, and Why"},{day:"Fri Apr 3",title:"Session 4 — Hold vs. Sell Analysis + 20-Question Quiz"}],vocabulary:[{term:"Lease Expiration Schedule",full:"Lease Expiration Schedule",definition:"A timeline showing when each tenant's lease expires across a portfolio. Used to identify renewal risk concentration (multiple leases expiring simultaneously), mark-to-market opportunities (below-market leases expiring), and capital need timing. The fundamental asset management planning tool.",example:"Portfolio: Tenant A (45K SF) expires Q1 2026; Tenant B (80K SF) expires Q3 2026; Tenant C (30K SF) expires Q4 2027. Q3 2026 is a major risk/opportunity concentration."},{term:"Rollover Risk",full:"Rollover (Lease Expiration) Risk",definition:"The risk that a tenant does not renew their lease at expiration, creating vacancy and requiring re-leasing costs (leasing commissions, tenant improvements, downtime). Concentrated rollover (multiple expirations in same period) compounds the risk. Managed by staggering lease terms and proactive renewal outreach.",example:"A 200K SF single-tenant industrial building: entire income stream expires in one date. If tenant leaves, 100% vacancy overnight — maximum rollover risk concentration."},{term:"Mark-to-Market Opportunity",full:"Mark-to-Market Rent Opportunity",definition:"The upside from resetting a below-market in-place lease to current market rent at expiration. Quantified as: (market rent − in-place rent) × SF × 12. A key value-add driver. Captured at lease expiration through new lease negotiation or by re-tenanting at market rate.",example:"In-place rent: $1.50/SF/mo NNN. Market rent: $2.00/SF/mo. 100K SF. Mark-to-market uplift = $0.50 × 100K × 12 = $600K/yr additional NOI."},{term:"CapEx Plan",full:"Capital Expenditure Plan",definition:"A multi-year schedule of planned capital investments to maintain or improve the property: roof replacement, HVAC, parking lot, dock levelers, and tenant improvements. Funded from reserves or capital calls. Good CapEx planning prevents deferred maintenance that reduces asset value and tenant satisfaction.",example:"Year 1: Roof $180K; Year 2: Parking lot $95K; Year 3: HVAC replacement $220K; Year 4: Dock levelers $60K. Total 4-year CapEx plan: $555K."},{term:"Hold vs. Sell",full:"Hold vs. Sell Analysis",definition:"A financial analysis comparing the risk-adjusted returns of continuing to hold an asset against selling at today's price. Triggered by: lease expirations, significant value creation, cap rate compression, pending CapEx needs, or portfolio rebalancing. The central ongoing decision in asset management.",example:"Asset at $22M value with $1.1M NOI (5.0% cap). Hold scenario: 3% NOI growth, 5.25% exit cap in 5 years = 14% projected IRR. Sell today at $22M. Is 14% worth the hold risk vs. redeploying $22M in a new opportunity?"},{term:"Asset Management Fee",full:"Asset Management Fee",definition:"Annual fee paid to the GP/manager for ongoing asset management: lease negotiations, maintenance oversight, financial reporting, and strategic decision-making. Typically 1–2% of revenues or 1% of property value annually. Reduces LP distributable cash flow but compensates for ongoing active management.",example:"Property generates $1.2M NOI; 1.5% asset management fee on revenues = $1.2M × 1.5% = $18,000/yr fee to GP. Reduces LP distributable cash flow."}],quiz:[{q:"A lease expiration schedule shows three major tenants all expiring in Q2 2027. This creates:",opts:["A buying opportunity for new tenants","Significant rollover risk concentration — potentially losing multiple tenants simultaneously, creating large vacancy and re-leasing costs","An opportunity to raise rents immediately","No concern if the market is strong"],a:1,exp:"Concentrated expirations = concentrated rollover risk. Three expirations in one quarter could create sudden, severe vacancy and require simultaneous re-leasing of multiple spaces — stretching management capacity and creating cash flow stress."},{q:"Rollover risk is LOWEST for which tenant profile?",opts:["Month-to-month tenant paying above-market rent","A credit tenant with a 10-year NNN lease signed 2 years ago with 2 renewal options","A tenant whose lease expires in 6 months","A startup company in its first year of occupancy"],a:1,exp:"Long-term lease (10 years) + renewal options + credit tenant = low rollover risk. High probability of renewal, long time before risk crystallizes, and options extend the lease term further if exercised."},{q:"Mark-to-market uplift: in-place rent $1.60/SF/mo NNN; market $2.10/SF/mo; 60,000 SF. Annual NOI increase at lease expiration:",opts:["$30,000","$360,000","$540,000","$180,000"],a:1,exp:"($2.10 − $1.60) × 60,000 × 12 = $0.50 × 60,000 × 12 = $360,000/yr."},{q:"A CapEx plan helps asset managers primarily by:",opts:["Reducing the need for tenant improvements","Anticipating and budgeting for major capital expenditures before they become emergency expenses, protecting asset quality and cash flow predictability","Eliminating all future property expenses","Justifying higher rents to tenants"],a:1,exp:"Proactive CapEx planning converts unpredictable emergency repairs into planned, budgeted investments. A roof that fails unexpectedly is an emergency; a roof replacement scheduled 2 years out is a line item in the CapEx plan."},{q:"A typical industrial property CapEx reserve is approximately:",opts:["$0.05–$0.10/SF/year","$0.15–$0.35/SF/year","$1.00–$2.00/SF/year","$5.00/SF/year"],a:1,exp:"Industrial properties are relatively low-maintenance compared to office or multifamily. Standard reserves: $0.15–$0.35/SF/year for basic industrial (single-story tilt-up). Office: $2–$5/SF/yr. Multifamily: $200–$400/unit/yr."},{q:"An asset manager reviews a building where the HVAC was last replaced 18 years ago (typical life 20–25 years). The right action is:",opts:["Do nothing until the HVAC fails","Budget HVAC replacement in the CapEx plan within 2–5 years — proactive replacement prevents emergency failure and potential lease default","Pass the cost to the tenant regardless of lease terms","Reduce the asking rent to attract tenants who will pay for HVAC themselves"],a:1,exp:"Proactive CapEx planning: HVAC at 18 years needs to be in the 3–5 year CapEx plan. Emergency HVAC failure during summer = tenant emergency = potential lease dispute. Budget it, schedule it, manage it."},{q:"Deciding to SELL an asset today vs. hold for 5 more years should primarily consider:",opts:["The original purchase price (sunk cost)","Forward IRR of holding vs. risk-adjusted return from redeploying the sale proceeds into a new opportunity","How much the property has appreciated since acquisition","The broker's recommendation"],a:1,exp:"Hold vs. sell is a forward-looking analysis. Sunk costs are irrelevant. Compare: what will I earn holding this asset for 5 more years (lease risk, CapEx needs, NOI growth, exit value) vs. selling today and redeploying in a better-return opportunity?"},{q:"A tenant represents 85% of a building's revenue on a lease expiring in 18 months. What should the asset manager do now?",opts:["Wait until 6 months before expiration to start renewal discussions","Begin renewal discussions immediately — 18 months is the right lead time for a major tenant. Offer early renewal incentives to reduce rollover risk and preserve occupancy","Assume the tenant will renew — 85% of buildings retain their major tenants","Market the space for replacement immediately"],a:1,exp:"The earlier you engage a major tenant on renewal, the more leverage you have to retain them. 18 months is appropriate lead time. Waiting until 6 months leaves you no time to find a replacement if they decide to leave."},{q:"Portfolio of 5 industrial buildings: all with leases expiring in 2027. An asset manager should:",opts:["Sell all 5 buildings in 2026 to avoid rollover risk","Proactively begin renewal outreach, stagger future lease terms at renewal, budget re-leasing costs, and stress-test cash flow during any gap periods","Wait to see if tenants renew before acting","Extend all leases at current rents to eliminate risk"],a:1,exp:"Concentrated portfolio rollover requires systematic management: early renewal outreach, staggered terms at renewal, budgeted CapEx and TIs, and a hold period that accounts for lease-up scenarios."},{q:"Asset management fee of 1.5% of effective gross revenues on a property generating $2.0M EGI equals:",opts:["$30,000/yr","$300,000/yr","$150,000/yr","$20,000/yr"],a:0,exp:"$2.0M × 1.5% = $30,000/yr. Note: asset management fees are typically small relative to NOI, but they accumulate across a portfolio."},{q:"A 3-year hold with a 2-year lease expiration remaining creates what challenge for the exit?",opts:["No challenge — buyers prefer short lease terms","The building will be in rollover risk during the buyer's hold period — reducing buyer's willingness to pay a core premium and potentially requiring a lease-up discount","The seller must renew the lease before selling","IRR automatically increases when lease terms are short"],a:1,exp:"Buyers discount properties with near-term lease expirations because they are buying rollover risk. A 2-year remaining lease means the buyer faces re-leasing within 2 years of acquisition — they'll price this uncertainty into their offer."},{q:"Which event most strongly suggests selling an asset now rather than continuing to hold?",opts:["Cap rates expanding 25 bps","The property is fully leased at market rent, no near-term CapEx needed, and a competing buyer has appeared willing to pay at a cap rate lower than your projected exit","NOI grew 3% last year","The loan maturity is in 4 years"],a:1,exp:"Sell signals: (1) fully stabilized — no more upside from operations, (2) no CapEx burden — clean story for buyer, (3) aggressive buyer willing to pay your target exit price. This is the optimal sell scenario."},{q:"A 200K SF industrial portfolio with $0.20/SF/yr CapEx reserve needs how much annual CapEx reserves?",opts:["$20,000","$40,000","$200,000","$400,000"],a:1,exp:"200,000 SF × $0.20/SF = $40,000/yr CapEx reserve."},{q:"Proactive renewal of a below-market lease (to lock in a good tenant for 5 more years) creates what tradeoff?",opts:["No tradeoff — always renew early","Lock in tenant stability but forfeit the near-term mark-to-market opportunity. The decision depends on whether rollover risk or rent upside is more material.","Always renew at above-market rent","Rollover risk is always worth accepting for the rent upside"],a:1,exp:"Early renewal at below-market rent = tenant stays (reduces vacancy risk) but forgoes mark-to-market opportunity. Decision depends on tenant quality, market conditions, and how below-market the rent is. Good tenants at slight discount may beat re-leasing risk."},{q:"A hold vs. sell analysis shows: hold 5 more years = projected 13% IRR; sell today and redeploy = projected 17% IRR in next acquisition. The analysis suggests:",opts:["Hold — never sell a performing asset","Sell — higher risk-adjusted return from redeployment makes selling the superior financial decision","Sell only if the gain is more than $1M","Neither — average the two returns and hold half"],a:1,exp:"Capital should be deployed where it earns the highest risk-adjusted return. If selling and redeploying delivers 17% vs. 13% holding, sell — assuming the 17% opportunity is genuine and risk-equivalent."},{q:'What does "staggered lease expiration" mean in portfolio asset management?',opts:["All tenants have the same lease expiration date","Lease expirations are spread across different years — reducing the risk of simultaneous vacancy and spreading the re-leasing workload over time","All leases are month-to-month","Tenants can choose when their leases expire"],a:1,exp:"Staggered expirations = risk mitigation. If Tenant A expires 2025, B expires 2027, C expires 2029, you face one re-leasing event at a time rather than all three at once. This is the primary lease scheduling goal in portfolio asset management."},{q:"A tenant requests a 5-year lease extension at in-place rent ($1.55/SF/mo) when market is $2.10/SF/mo. The asset manager should:",opts:["Refuse — always demand market rent immediately","Negotiate: offer a renewal at a blend (e.g., $1.75/SF now stepping to $1.95/SF in Year 3) that retains the tenant while capturing partial mark-to-market","Accept immediately — tenant retention is paramount","Reject and start marketing the space for a new tenant at $2.10"],a:1,exp:"Negotiation: a blend-and-extend captures some mark-to-market while retaining a proven tenant. Pure tenant replacement at market maximizes rent but risks vacancy. Pure renewal at in-place rent leaves money on the table. A blended step-up balances both."},{q:'Asset managers track "weighted average lease term" (WALT) because:',opts:["It equals the average lease term in the portfolio","WALT weighted by SF or NOI measures the portfolio's average remaining lease term — longer WALT = more income certainty, lower rollover risk, lower risk premium for buyers","It determines the property's depreciation schedule","WALT sets the CapEx reserve requirement"],a:1,exp:"WALT is the primary lease risk metric for CRE portfolios. Buyers price longer WALT at lower cap rates (higher values) because income certainty is higher. Short WALT = rollover risk = cap rate premium = lower price."},{q:"In an Infinity Capital asset management review, three buildings show: Building A (WALT 7.5 yrs, below-market rents), Building B (WALT 2.5 yrs, market rents), Building C (WALT 0.5 yrs, above-market rents). Rollover risk ranking from highest to lowest:",opts:["A > B > C","C > B > A","B > C > A","All equal"],a:1,exp:"Rollover risk = short remaining lease term. C (0.5 yr) is highest risk — expiring imminently. B (2.5 yr) is next. A (7.5 yr) is lowest risk. Note: C has above-market rents, meaning renewal may mean rent reduction — additional income risk at expiration."}]},10:{sessions:[{day:"Mon Apr 6",title:"Session 1 — Vocabulary: 1031 Exchange, QI, Identification Period, Like-Kind, Boot, Depreciation Recapture"},{day:"Wed Apr 8",title:"Session 2 — 1031 Exchange Mechanics: 45-Day Rule, 180-Day Rule, QI Role"},{day:"Thu Apr 9",title:"Session 3 — Outright Sale vs. 1031 vs. Refinance: After-Tax Comparison"},{day:"Fri Apr 10",title:"Session 4 — Depreciation Recapture and Capital Gains Analysis + 20-Question Quiz"}],vocabulary:[{term:"1031 Exchange",full:"1031 Tax-Deferred Exchange",definition:"A provision in IRS Section 1031 allowing an investor to defer capital gains taxes when selling a qualifying investment property — as long as proceeds are reinvested into a like-kind replacement property within strict timelines. The most powerful tax deferral tool in CRE. Can be used repeatedly to defer taxes indefinitely.",example:"Sell Long Beach industrial for $20M ($15M gain). Instead of paying $3M+ in capital gains tax, do a 1031 exchange into a Phoenix multifamily deal — defer all taxes and reinvest the full $20M."},{term:"QI",full:"Qualified Intermediary",definition:`A third-party facilitator required to execute a 1031 exchange. The seller's proceeds go directly to the QI (not the seller) to avoid "constructive receipt." The QI holds funds during the exchange period and wires them to buy the replacement property. If proceeds touch the seller's account, the exchange fails.`,example:"HTA sells industrial building; QI receives $8M proceeds at closing. HTA identifies replacement within 45 days, QI wires funds to close replacement property within 180 days."},{term:"Identification Period",full:"45-Day Identification Period",definition:"The IRS-mandated 45-day window from the sale of the relinquished property during which the investor must formally identify potential replacement properties in writing to the QI. Strict deadline — no extensions except for federally declared disasters. Must identify at least 1 property (can identify up to 3 under the 3-property rule).",example:"Sale closes July 1. Deadline: August 15 (45 days). Investor must identify replacement property in writing to QI by August 15 or exchange fails."},{term:"Like-Kind Property",full:"Like-Kind Replacement Property",definition:'Under Section 1031, real property held for investment or business use qualifies as "like-kind" to other real property held for investment or business use — regardless of property type. Industrial can exchange into multifamily; retail can exchange into office. Like-kind is broad for real property; primary residences do NOT qualify.',example:"Relinquished: Long Beach industrial warehouse. Replacement: Phoenix multifamily complex. Both held for investment → like-kind exchange qualifies."},{term:"Boot",full:"Boot (Taxable Portion of Exchange)",definition:"Any portion of exchange proceeds that is NOT reinvested into like-kind property — received as cash, debt relief, or personal property. Boot is taxable. To fully defer all taxes, the replacement property must be equal or greater in value, and all proceeds must be reinvested. Partial reinvestment = partial tax owed on the boot.",example:"Sell for $10M; buy replacement for $8.5M. $1.5M boot received → taxable. If gain was $6M, and boot is $1.5M, $1.5M of the $6M gain is currently taxable."},{term:"Depreciation Recapture",full:"Depreciation Recapture (Section 1250)",definition:"When a commercial property is sold, the IRS recaptures depreciation deductions taken during ownership at a flat 25% federal rate (vs. 20% long-term capital gains rate). Cannot be deferred in a 1031 exchange if the replacement property has less depreciable basis. A significant tax consideration at disposition.",example:"Took $1.5M in depreciation over 10-year hold. At sale, $1.5M recaptured at 25% rate = $375,000 in depreciation recapture tax (on top of capital gains on any appreciation)."},{term:"Exchange Period",full:"180-Day Exchange Period",definition:"The IRS-mandated 180-day window from the relinquished property sale to close on the identified replacement property. The 45-day ID period runs concurrently within the 180-day window. Failure to close within 180 days results in a failed exchange and full tax liability on the gain.",example:"Sale closes July 1. Must close replacement by December 28 (180 days). The 45-day ID deadline (Aug 15) is within this window."}],quiz:[{q:"A 1031 exchange allows an investor to:",opts:["Eliminate capital gains taxes permanently","Defer capital gains taxes by reinvesting sale proceeds into a like-kind replacement property within required timelines","Sell property tax-free if held for more than 10 years","Avoid all taxes including depreciation recapture"],a:1,exp:"1031 defers (does not eliminate) capital gains tax. Taxes are paid when the replacement property is eventually sold without a subsequent 1031. Used repeatedly, taxes can be deferred across multiple cycles."},{q:"The 45-day rule in a 1031 exchange requires:",opts:["Closing on the replacement property within 45 days","Formally identifying replacement properties in writing to the QI within 45 days of the relinquished property sale","Receiving exchange funds from the QI within 45 days","Completing depreciation recapture within 45 days"],a:1,exp:"45 days from relinquished sale: formal written identification of replacement properties to QI. This is a hard IRS deadline with essentially no extensions."},{q:"If sale proceeds touch the investor's personal bank account during a 1031 exchange:",opts:["The exchange still qualifies if reinvested within 180 days","The exchange fails — constructive receipt of proceeds disqualifies the exchange and triggers full capital gains tax","The investor has 30 days to return the funds to the QI","Only the amount received is taxable, not the full gain"],a:1,exp:"Constructive receipt rule: if the investor ever has control over the proceeds (even briefly), the 1031 fails completely. All proceeds must flow directly to the QI — never through the seller's accounts."},{q:"Can an investor exchange a Long Beach industrial building for a Phoenix apartment complex in a 1031?",opts:["No — must be the same property type","Yes — both are investment real estate and qualify as like-kind regardless of property type","Only if both are NNN leased","Only if both are in California"],a:1,exp:"Like-kind for real property is broad: any investment real property exchanged for any other investment real property qualifies. Cross-asset class and cross-state exchanges are permitted."},{q:'"Boot" in a 1031 exchange is:',opts:["The QI's fee for executing the exchange","The taxable portion — any proceeds not reinvested into like-kind property (cash received, net debt relief, or personal property received)","The identification letter sent to the QI","The replacement property's title insurance"],a:1,exp:"Boot = taxable cash or debt relief not reinvested. To defer 100% of gain, reinvest 100% of proceeds and acquire equal or greater debt. Any shortfall = boot = current-year taxable income."},{q:"Sell $15M industrial; $9M gain (original basis $6M). Buy replacement for $13M (took $2M boot). How much of the gain is taxable?",opts:["$9M — full gain taxable","$2M — only the boot triggers tax","$7M — gain minus boot","$0 — partial exchange defers all"],a:1,exp:"In a partial exchange, gain is recognized to the extent of boot received. $2M boot received = $2M gain recognized and taxable. Remaining $7M of gain deferred into replacement property basis."},{q:"The 180-day exchange period starts:",opts:["When the investor signs the 1031 agreement","On the date the relinquished property sale closes","When the QI identifies the replacement property","45 days after the relinquished property sale"],a:1,exp:"Both the 45-day and 180-day periods start on the relinquished property closing date. They run concurrently — identification by day 45, closing by day 180."},{q:"Depreciation recapture is taxed at what federal rate?",opts:["0% — depreciation recapture is not taxed separately","25% — flat rate on recaptured depreciation, separate from long-term capital gains rate (20%)","20% — same as long-term capital gains","37% — ordinary income rate"],a:1,exp:"Section 1250 depreciation recapture on commercial real estate is taxed at 25% federal rate, higher than the 20% long-term capital gains rate. This is a significant cost basis consideration at disposition."},{q:"An investor took $2M in depreciation over 12 years. Building sells at $800K gain above depreciated basis. Taxes owed include:",opts:["$800K gain only at 20% = $160K","$2M at 25% recapture ($500K) + $800K at 20% LTCG ($160K) = $660K total federal tax","$2M at 37% ordinary income = $740K","$0 — 1031 eliminates all taxes"],a:1,exp:"Two tax events at sale: (1) Recapture $2M of depreciation at 25% = $500K. (2) Long-term gain on remaining appreciation at 20% = $160K. Total federal: ~$660K (plus state). This is why 1031 exchanges are so valuable — deferring $660K in taxes keeps that capital working."},{q:"A primary residence does NOT qualify for 1031 because:",opts:["Residences are too small","1031 requires property held for investment or business use — a primary residence is personal use property and is excluded","Residential properties have no capital gains","Residences can only be exchanged for other residences"],a:1,exp:"1031 applies to investment or business-use real property. Personal residences are excluded. Note: the Section 121 exclusion ($250K/$500K gain exclusion) applies to primary residences instead."},{q:"An investor owns Long Beach industrial worth $22M, original basis $6M, $4M depreciation taken (depreciated basis $2M). Full sale gain = $22M − $2M = $20M. Depreciation recapture portion is:",opts:["$20M at 25%","$4M at 25% recapture rate; $16M at 20% LTCG rate","$6M at 25%","$22M at 37%"],a:1,exp:"Tax layers: $4M depreciation recaptured at 25% = $1M tax. Remaining $16M appreciation at 20% LTCG = $3.2M. Total federal: ~$4.2M. A 1031 can defer this entire $4.2M if reinvested properly."},{q:"Under the 3-property identification rule, an investor can identify up to __ replacement properties within 45 days:",opts:["1","3","5","Unlimited"],a:1,exp:"The 3-property rule: an investor can identify up to 3 properties of any value as potential replacements. Alternatively, the 200% rule allows identifying unlimited properties as long as total identified value ≤ 200% of relinquished value."},{q:'Why is a 1031 exchange described as a "tax deferral" not "tax elimination"?',opts:["The taxes are eliminated after 10 years","The gain is carried forward in the replacement property's lower basis — when the replacement is eventually sold without a 1031, all deferred gains become taxable","Depreciation recapture is still owed immediately","State taxes cannot be deferred"],a:1,exp:`The replacement property's basis is reduced by the deferred gain. When eventually sold, the accumulated deferred gains (from all prior 1031s) become taxable. Exception: stepped-up basis at death can eliminate deferred gain permanently — sometimes called the "1031 forever" strategy.`},{q:"Outright sale vs. 1031 exchange vs. cash-out refinance: which option generates no current taxable event?",opts:["Outright sale — pay capital gains and invest net proceeds","1031 exchange (if properly executed) or cash-out refinance — both defer or avoid current taxation","Cash-out refinance only","All generate current tax"],a:1,exp:"A properly executed 1031 defers capital gains. A cash-out refinance (borrowing against equity) generates no taxable event — loan proceeds are debt, not income. Both preserve capital for reinvestment. Outright sale triggers capital gains and recapture immediately."},{q:"An investor closes a sale on August 1. The 45-day identification deadline is:",opts:["September 1","September 15","October 1","July 31 of next year"],a:1,exp:"August 1 + 45 days = September 15. Count calendar days from closing date."},{q:"The QI's primary function is to:",opts:["Negotiate the replacement property purchase price","Hold exchange proceeds in escrow between the sale of the relinquished property and the purchase of the replacement — ensuring the investor never has constructive receipt","File the 1031 with the IRS","Identify replacement properties for the investor"],a:1,exp:"QI safeguards the exchange by holding proceeds. The investor has no access to funds during the exchange period. QI also prepares the exchange agreement and coordinates with closing agents."},{q:"Infinity Capital completes a 1031 exchange: sells Long Beach industrial at $25M gain, defers all taxes into a Phoenix industrial portfolio. 7 years later, sells Phoenix portfolio for $40M gain. Total deferred gain now:",opts:["$25M only from original exchange","$25M original + $40M new gain = $65M total deferred (assuming another 1031), or $65M taxable if sold outright","$40M new gain only","$0 — after 7 years, original gain expires"],a:1,exp:"Each successive 1031 carries forward accumulated deferred gains plus new appreciation. After two deferred exchanges with $25M + $40M = $65M total deferred gain, a final sale without 1031 triggers $65M in recognized gain. The longer you defer, the larger the eventual tax bill — but the longer your capital compounds tax-free."},{q:"An investor needs to close on a $20M replacement property within the 180-day exchange window. The original sale closed January 15. The replacement must close by:",opts:["June 15","July 14","July 15","February 15"],a:1,exp:"January 15 + 180 days = July 14. Note: 45-day ID deadline is March 1 (Jan 15 + 45 days)."},{q:"In a high-interest rate environment, why might a cash-out refinance be preferred over a 1031 exchange?",opts:["Refinancing avoids all state taxes","1031 requires buying a replacement — if good replacement deals are scarce or overpriced, a refinance extracts equity tax-free without forcing deployment into a mediocre deal","Refinancing has no closing costs","The 180-day deadline is waived in high-rate environments"],a:1,exp:'A 1031 forces you to deploy into a replacement property. In markets where good deals are hard to find (high prices, limited inventory), a refinance lets you extract equity without the reinvestment obligation — avoiding a forced "bad 1031" into an overpriced deal.'},{q:"Which of these parties does NOT need to be involved in a valid California 1031 exchange?",opts:["Qualified Intermediary (QI)","Both closing agents (relinquished and replacement escrow companies)","The California Board of Equalization","Title insurance companies for both properties"],a:2,exp:'The California Board of Equalization handles sales tax — not relevant to 1031 exchanges. A valid CA 1031 requires: QI, closing agents on both ends, and title companies. The IRS and state FTB require proper reporting, but no state agency must be "involved" in the transaction mechanics.'}]},11:{sessions:[{day:"Mon Apr 13",title:"Session 1 — Vocabulary: Investment Thesis, Market Overview, Underwriting Assumptions, IC"},{day:"Wed Apr 15",title:"Session 2 — Investment Memo Structure: From Thesis to Risk to Recommendation"},{day:"Thu Apr 16",title:"Session 3 — Sensitivity Analysis in an IC Memo: What the Committee Wants to See"},{day:"Fri Apr 17",title:"Session 4 — Writing a Go/No-Go Recommendation + 20-Question Quiz"}],vocabulary:[{term:"Investment Thesis",full:"Investment Thesis",definition:'The core argument for why a specific investment will generate target returns. Connects market fundamentals (demand drivers, vacancy, rent growth), asset-specific opportunity (value-add, location, basis), and execution strategy. Must be specific, differentiated, and supported by data — not just "SoCal industrial is good."',example:'"Port-proximate Long Beach industrial with 18-month lease expiration at 74% of market rent; acquire below replacement cost; mark-to-market at expiration; exit at market cap. Basis: $185/SF vs. $260/SF replacement cost."'},{term:"Market Overview",full:"Market Overview Section",definition:"The market analysis section of an investment memo documenting the macro and submarket context: vacancy, absorption, rent growth, supply pipeline, and demand drivers. Provides the evidence base for rent growth and exit cap rate assumptions in the underwriting.",example:"Long Beach industrial submarket: 2.8% vacancy; +2.1M SF absorption YTD; $1.95/SF/mo avg asking rent (up 6% YoY); 800K SF pipeline (0.8% of inventory). Supports 3.0% annual rent growth assumption."},{term:"Underwriting Assumptions",full:"Underwriting Assumptions",definition:"The specific numerical inputs in the financial model: going-in NOI, rent growth rate, vacancy/lease-up period, renovation budget, exit cap rate, hold period, financing terms. Each assumption must be supported by market data or deal specifics. The IC will challenge every assumption — know your support.",example:"Assumptions: going-in NOI $920K; 3.0% annual rent growth; 9-month lease-up at 55% occupancy; $12/SF renovation; 5.0% exit cap; 5-year hold; 65% LTV bridge loan at SOFR+275."},{term:"Sensitivity Analysis",full:"Sensitivity Analysis (Investment Memo)",definition:"A table showing how returns (IRR, equity multiple) change under different assumptions for key inputs. The IC will stress exit cap rate (most sensitive) and rent growth. A well-presented sensitivity table shows base, upside, and downside scenarios with labeled assumptions — demonstrating that the deal still works under reasonable stress.",example:"Sensitivity table: rows = exit cap (4.75%, 5.00%, 5.25%, 5.50%); columns = rent growth (2%, 3%, 4%). Base = 5.00% / 3.0% = 16.2% IRR. Stress = 5.50% / 2.0% = 12.8% IRR."},{term:"Risk Mitigants",full:"Risk and Mitigant Analysis",definition:"A section of the investment memo that identifies the top 3–5 risks to the investment thesis and pairs each with a specific mitigating factor. Demonstrates intellectual honesty and analytical rigor — an IC that sees risks you haven't identified will lose confidence in your memo.",example:"Risk: tenant does not renew at lease expiration. Mitigant: signed LOI from replacement tenant at market rate; deep broker relationships in Long Beach industrial submarket."},{term:"Investment Committee",full:"Investment Committee (IC)",definition:"The decision-making body that approves or rejects investment proposals. Composed of senior principals (often the GP's partners or key LP representatives). Evaluates the memo, challenges assumptions, tests stress scenarios, and votes on go/no-go. IC approval required before committing capital.",example:"Infinity Capital IC: Peter Parada + Tom HTA + LP representative. IC meeting: 60-minute presentation, 30-minute Q&A, vote on go/no-go, approved/rejected with conditions."}],quiz:[{q:"An investment thesis must be:",opts:["Optimistic about all market conditions","Specific, data-supported, and differentiated — connecting market conditions to asset-specific opportunity and execution strategy","Written by an outside broker","Approved by the tenants before IC presentation"],a:1,exp:'A strong thesis tells the IC: (1) why this market/submarket, (2) why this asset specifically, (3) what we will do to create value, (4) why we will succeed. Generic statements ("SoCal is a great market") without specific asset analysis are not investment theses.'},{q:"The market overview section of an investment memo is used to:",opts:["Describe the property's physical characteristics","Support the rent growth and exit cap rate assumptions with data-driven market context","List the broker contacts in the market","Calculate the going-in cap rate"],a:1,exp:'Market overview evidence-bases the model. If you assume 3% rent growth, the market section shows why (2.8% vacancy, positive absorption, limited pipeline). IC will ask "why 3%?" — your market section is the answer.'},{q:"The most challenged underwriting assumption in an industrial investment IC presentation is typically:",opts:["The going-in NOI","The exit cap rate — most sensitive input, hardest to predict, largest impact on total return","The lease-up timeline","The acquisition price"],a:1,exp:'Exit cap rate drives reversion value, which is 60–80% of total DCF value. A 50-bps change in exit cap creates a $2M+ swing in a typical deal. IC will always ask: "What if the exit cap is 50 bps higher? Still works?"'},{q:"A sensitivity table in an investment memo should show:",opts:["Only the best-case scenario to maximize IC enthusiasm","Base case, upside, and downside across the 2–3 most sensitive inputs — demonstrating the deal performs acceptably under reasonable stress","All possible scenarios (thousands of combinations)","Only the downside to be conservative"],a:1,exp:"A good sensitivity table shows: (1) base case (management's best estimate), (2) upside (optimistic but possible), (3) downside (realistic bad scenario). Shows IC the range of outcomes without hiding risks."},{q:"A risk/mitigant section strengthens an investment memo by:",opts:["Admitting the deal might fail","Demonstrating the analyst thought critically about what could go wrong AND has specific responses — building IC confidence in the analysis","Reducing the target IRR to be conservative","Identifying risks so the IC can reject the deal"],a:1,exp:`ICs know every deal has risks. Explicitly identifying risks and pairing them with credible mitigants shows intellectual rigor. An analyst who says "no significant risks" loses more credibility than one who says "here are 4 risks and here's how we manage them."`},{q:"An investment memo go/no-go recommendation should be:",opts:['Always "go" — why would you bring a "no-go" to IC?','Clear, specific, and conditional if relevant: "recommend acquisition at ≤$XX/SF acquisition price, subject to environmental clearance and lease execution with Tenant A"',"Vague to avoid commitment","Based solely on the broker's view"],a:1,exp:`A good recommendation is specific: recommends acquisition at a defined price/terms, flags any conditions (diligence items, LOI execution), and clearly states the analyst's view. "We recommend proceeding" without conditions is incomplete; "we pass" without rationale is useless.`},{q:"IC will typically ask which question FIRST about a value-add industrial memo?",opts:["What is the broker's commission?",`"What happens to returns if the tenant doesn't renew and lease-up takes 18 months instead of 9?" — lease-up risk is the core value-add risk`,'"Is the building LEED certified?"',`"What was the seller's original purchase price?"`],a:1,exp:"IC zeroes in on the biggest risk in any value-add industrial deal: lease-up. Extended vacancy = lost income = lower IRR. The IC wants to see: (1) you've stress-tested it, (2) the deal still works at extended lease-up, (3) you have a plan for re-tenanting."},{q:"An investment memo's market section shows 2.8% industrial vacancy and 3% asking rent growth YoY. The model assumes 4% annual rent growth for 10 years. The IC will likely say:",opts:["Approved — 4% is conservative vs. market","Challenge the 4% assumption: current growth is 3%, and 4% compounded over 10 years implies above-trend performance. Justify or reduce to 3%.","Approved — higher rent growth makes the deal better","Pass — any rent growth assumption over 3% is aggressive"],a:1,exp:"Model assumptions must align with or be explained vs. market data. 4% model vs. 3% current growth is a 100-bps gap that IC will challenge. Either justify (historical CAGR supports 4%, near-term pipeline is limited) or adjust to 3%."},{q:'What does a "waterfall sensitivity table" show in a JV investment memo?',opts:["Cap rate vs. rent growth matrix only","How LP and GP returns change at different IRR outcomes — useful for showing LP that they hit their preferred return in base and stress cases","The property's drainage system","Annual cash flow distribution"],a:1,exp:"A waterfall sensitivity shows LP and GP economics at various overall deal IRRs: does LP pref get paid even in stress case? At what IRR does GP earn its full promote? Demonstrates to LP that their downside is protected."},{q:"The investment committee will typically approve a deal if:",opts:["IRR exceeds the hurdle in the base case only","Base case IRR exceeds hurdle, stress case IRR remains acceptable, key risks are identified with credible mitigants, and the analyst can defend every assumption","The property is in SoCal","The broker recommends it strongly"],a:1,exp:"IC approval requires: base case above hurdle, acceptable downside, identified risks with mitigants, and a confident, knowledgeable presenter who can defend the underwriting under scrutiny. Any undefended assumption undermines the entire memo."},{q:"A Long Beach industrial investment memo has a base case IRR of 16.5% and a stress case (6-month extended lease-up + 50 bps exit cap expansion) of 11.0%. IC target is 14% minimum. You should:",opts:["Present only the base case","Present both cases; acknowledge the stress case misses target; propose strategies to improve stress case (lower acquisition price, pre-leasing, better renovation plan)","Adjust the stress case assumptions to hit 14%","Pass on the deal immediately"],a:1,exp:"Honest presentation builds IC credibility. Identify why stress fails and propose mitigants: negotiate lower price (improves all scenarios), pursue pre-leasing LOI (reduces lease-up risk), or accept that stress at 11% is acceptable risk given the base case upside."},{q:'When presenting underwriting assumptions, the presenter should be able to answer: "Where did this number come from?"',opts:["Only for the acquisition price","For EVERY assumption — each input should have a market data source, comparable transaction, or deal-specific justification","Only for the return metrics","Just for the rent growth and exit cap"],a:1,exp:`IC trust is built assumption by assumption. "We used 3% rent growth because CBRE's 2024 market report shows 3-year CAGR of 3.1% for Long Beach industrial" builds more confidence than "we felt 3% was reasonable." Every number needs a source.`},{q:"Investment memo executive summary should be:",opts:["2–3 pages detailing all financial calculations","Half a page to one page: deal summary, investment thesis, key return metrics, top risks, and recommendation — enough for a busy IC member to understand the deal in 3 minutes","The same as the full memo but bolded","Written after IC approval"],a:1,exp:"Executive summary = decision brief. Senior IC members often read only the exec summary before the meeting. It must stand alone: what is the deal, why do we like it, what do we make, what could go wrong, and do we recommend it."},{q:`After an IC meeting, an IC member says: "I like the deal but I'm concerned about lease-up timing. Can you get a letter of intent from a replacement tenant before we commit?" This is:`,opts:["A rejection — don't proceed","A conditional approval — IC is interested but wants a specific risk mitigant executed before committing capital","Standard IC procedure — always get LOIs before any deal","A request to rewrite the investment memo"],a:1,exp:`Conditional approvals are common: "we'll approve subject to [specific condition]." The analyst's job is to satisfy the condition (get the LOI) and return to IC for final approval. Not a rejection — a risk mitigation request.`},{q:'Which of these belongs in the "underwriting assumptions" section of an industrial investment memo?',opts:["The seller's asking price history","Year 1 NOI, annual rent growth rate, vacancy rate, renovation budget, lease-up period, exit cap rate, and hold period — the specific model inputs with source justification","The broker commission agreement","The city's zoning map for the submarket"],a:1,exp:"Underwriting assumptions = the model inputs that the IC will scrutinize. Every key driver of return (NOI, growth, costs, timing, exit) should be stated with its supporting rationale."},{q:'An investment memo for an Infinity Capital Long Beach industrial deal concludes with "We recommend acquisition at a maximum price of $185/SF ($18.5M for 100K SF), contingent on Phase I environmental clearance and confirmation of the 5-year lease renewal option with Tenant A." This recommendation is:',opts:["Too conditional — remove the contingencies","Well-structured: clear price limit, identified contingencies, and specific conditions that must be met before committing","Too aggressive — recommend a lower price","Incomplete — needs broker sign-off"],a:1,exp:"A specific, conditional recommendation protects the investment: it commits to a maximum price (no bidding war), identifies environmental diligence as gating, and ensures the key lease option is confirmed before capital is at risk."},{q:"When writing the risk section of an investment memo, which risks should be included?",opts:["Only risks that are likely to happen","The top 3–5 material risks that could cause the deal to underperform, with each paired with a specific mitigant — not every conceivable risk","Only risks beyond the investor's control","Zero risks — stating risks makes the deal look bad"],a:1,exp:"Focus on material, deal-specific risks with paired mitigants: lease-up risk, renovation overrun, exit cap expansion, market softening. Include only risks that could materially move returns. Mitigants show how you'd respond."},{q:"A sensitivity table shows: at 5.25% exit cap and 3% rent growth = 15.5% IRR; at 5.75% and 2% = 11.5% IRR. IC target IRR = 14%. This tells you:",opts:["The deal always works","The deal hits target at base but misses under stress — the IC needs to decide whether the stress scenario is plausible and whether 11.5% is an acceptable downside","The deal always fails","The sensitivity table is wrong — results should be higher"],a:1,exp:"Sensitivity tables don't give yes/no — they show the return range. IC must judge: how likely is the stress scenario (5.75% exit cap, 2% growth)? If plausible, is 11.5% downside acceptable vs. the 15.5% upside? Good IC discussion extracts this judgment."},{q:"The final slide of an Infinity Capital IC presentation on a Long Beach industrial value-add deal should contain:",opts:["The full 10-year DCF model in detail","A clear summary: deal name, acquisition price, target returns (base and stress), top 2–3 risks with mitigants, and a direct recommendation with conditions","The QI agreement for the 1031 exchange","The lease comparables spreadsheet"],a:1,exp:"Final slide = decision-ready summary. IC members make a vote. Give them: what are we buying, what do we make, what could go wrong, and should we do it? Everything else in the memo is support for this final frame."}]},12:{sessions:[{day:"Mon Apr 20",title:"Session 1 — Vocabulary: Deal Presentation, Return Attribution, IC Recommendation, Full-Cycle Analysis"},{day:"Wed Apr 22",title:"Session 2 — Capstone Prep: Applying Domains 1–4 to a Live Infinity Capital Deal"},{day:"Thu Apr 23",title:"Session 3 — Capstone Presentation: IC Q&A Simulation with Peter and Tom"},{day:"Fri Apr 24",title:"Session 4 — Domain 4 Debrief and Full-Program Integration Review"}],vocabulary:[{term:"Deal Presentation",full:"IC Deal Presentation",definition:"The formal presentation to an investment committee covering the full investment case: market context, asset overview, investment thesis, financial model, return analysis, sensitivity table, risks and mitigants, and go/no-go recommendation. Must be concise, data-driven, and defensible under aggressive questioning.",example:"A 20-minute IC presentation on a Long Beach industrial acquisition: 5 slides — exec summary, market, underwriting, waterfall, and recommendation."},{term:"Return Attribution",full:"Return Attribution Analysis",definition:"Breaking down total IRR into its component sources: cash flow yield (NOI distributions), NOI growth (rent increases), and appreciation (exit cap rate change). Shows how much of the return comes from income vs. growth vs. capital gain. Helps IC understand return quality and risk.",example:"Total IRR 16%: 3% from current cash flow, 5% from NOI growth (rent mark-to-market), 8% from appreciation (exit cap compression). Predominantly appreciation-driven — higher risk profile."},{term:"Full-Cycle Analysis",full:"Full-Cycle Investment Analysis",definition:"Evaluating an investment from acquisition through hold period through exit — considering all phases: purchase, renovation/lease-up, stabilization, hold period management, and disposition. Ensures no phase is underweighted in the return analysis. The capstone skill for a complete CRE investment analyst.",example:"Full-cycle analysis: acquisition at 4.5% cap → renovation → lease-up → stabilization at 6.5% yield on cost → 5-year stabilized hold → exit at 5.0% cap. IRR: 17.5%."},{term:"IC Recommendation",full:"Investment Committee Recommendation",definition:`The analyst's clear go/no-go recommendation to the IC with specific conditions and rationale. The single most important sentence in an investment memo: "We recommend acquisition at a maximum price of $X, subject to [conditions], based on [thesis summary]." Requires courage and analytical conviction.`,example:'"We recommend proceeding at ≤$19.5M ($195/SF), subject to Phase I clearance and broker confirmation of active tenant relocation demand. Base case IRR: 16.5%; stress case: 12.8%. Risk-adjusted return exceeds IC hurdle."'},{term:"Infinity Capital",full:"Infinity Capital (HTA Investment Platform)",definition:"The investment and development arm of HTA Construction & Development, focused on acquiring, developing, and managing commercial real estate in the LA Basin. The builder/developer perspective combined with investment underwriting creates a competitive advantage in evaluating project feasibility, construction cost, and execution risk.",example:"Infinity Capital acquires a value-add Long Beach industrial building — HTA's construction expertise enables accurate renovation budgeting and faster execution vs. pure investment firms without GC capabilities."}],quiz:[{q:"Return attribution analysis for a value-add industrial deal shows 60% of IRR comes from the exit cap compression assumption. This indicates:",opts:["The deal is very safe","The deal is heavily dependent on cap rate movements — a risky assumption; stress-test the exit cap aggressively","The analysis is correct and complete","The IC should approve immediately"],a:1,exp:"High dependence on cap rate compression (exit cap below going-in cap) introduces market risk: if rates don't compress or if they expand, the return collapses. A well-structured value-add deal should generate returns primarily from NOI growth, not cap rate bets."},{q:"In a full-cycle industrial investment analysis, the acquisition phase due diligence should include:",opts:["Physical inspection only","Physical (building condition, environmental), financial (rent roll, operating history), legal (title, leases, entitlements), and market (comp rents, vacancy) diligence — all four dimensions","Financial model review only","Broker opinion of value only"],a:1,exp:"Full-cycle begins at acquisition diligence. Miss a physical (unknown deferred maintenance), financial (overstated NOI), legal (easement), or market (overestimated market rent) issue and every subsequent phase is compromised."},{q:"HTA's construction expertise gives Infinity Capital what specific competitive advantage in value-add industrial deals?",opts:["Access to lower-rate financing","Accurate renovation budgeting and faster execution — HTA can price construction scope precisely, avoid surprises, and self-perform some work faster than pure investors who must outsource all renovation management","Better broker relationships","Higher leverage capacity"],a:1,exp:"GP with in-house GC = lower renovation cost uncertainty and execution risk. A pure investor bids renovation work out and relies on a third-party GC. HTA/Infinity Capital knows their renovation costs from day-one underwriting and can execute the business plan with direct control."},{q:"A full-cycle analysis integrating all Domain 4 concepts requires which combination of skills?",opts:["Cap rates and comp analysis only","Cap rates + asset class analysis + comp valuation + DCF modeling + debt structuring + market dynamics + value-add underwriting + JV waterfall + asset management + disposition strategy","DCF and JV waterfall only","Market report reading only"],a:1,exp:"Full-cycle = all Domain 4 skills integrated: market drives assumptions, asset class determines strategy, comps validate pricing, DCF models cash flows, debt structures leverage, market data supports rent growth, value-add business plan drives execution, waterfall determines LP/GP economics, asset management holds the plan, and 1031/disposition optimizes exit."},{q:'The Infinity Capital capstone deal IC recommendation requires a clear go/no-go. What makes a "no-go" recommendation credible and respected?',opts:["Saying no is always the safest choice",`A no-go recommendation with specific, data-supported rationale (e.g., "basis too high relative to comps, stress case fails IC hurdle, lease-up risk too concentrated") demonstrates analytical rigor — IC respects disciplined analysts who will say no when the deal doesn't work`,"Never recommend no-go — it wastes IC's time","Say no-go only for legal problems"],a:1,exp:"Disciplined analysts who decline deals when the numbers don't work build more IC trust than analysts who always find a way to make the deal work. A no-go recommendation with clear rationale demonstrates the analysis is rigorous, not salesmanship."},{q:"Domain 4 Week 12 capstone tests ability to integrate which financial skills?",opts:["Only cap rate calculations","Cap rate mechanics → asset class analysis → comp valuation → 10-year DCF → debt structuring → market narrative → value-add underwriting → JV waterfall → asset management → disposition strategy — all integrated into a single, IC-ready investment memo","JV waterfall only","Market report reading only"],a:1,exp:"The capstone demonstrates full integration: no single week's skill stands alone. A real deal requires all skills simultaneously: what is the market context (W1, W2, W6), what is the asset worth (W3), what do we model (W4), how do we finance it (W5), what value-add strategy (W7), how does JV work (W8), how do we manage it (W9), and how do we exit (W10) — presented as an investment memo (W11)."},{q:'Return attribution showing 4% IRR from cash flow, 6% from rent/NOI growth, and 7% from appreciation = 17% total IRR. What is the "quality" assessment of this return?',opts:["Low quality — too dependent on appreciation","Balanced — roughly 1/3 each from cash flow, growth, and appreciation. The appreciation component should be stress-tested, but the deal doesn't rely solely on cap rate compression.","High quality — appreciation-driven returns are always superior","Cannot assess quality from return attribution alone"],a:1,exp:"A balanced attribution (income + growth + appreciation) is healthier than appreciation-only. If 14 of 17% comes from appreciation, the deal fails completely if cap rates don't move. A 1/3-each split means the deal generates real cash and NOI growth even if appreciation disappoints."},{q:"HTA/Infinity Capital is evaluating a Long Beach industrial deal. Construction estimates renovation at $8/SF vs. a competing investor's $15/SF estimate. This cost advantage could enable HTA to:",opts:["Bid more aggressively (higher acquisition price) while still hitting return targets","Acquire at a lower price than competitors while matching their return targets, or bid slightly higher and still outperform competitors on returns","Guarantee a faster lease-up","Reduce the exit cap rate assumption"],a:1,exp:"HTA's $7/SF renovation savings on a 100K SF building = $700K cost advantage. At a 5% exit cap, that $700K of additional NOI capacity = $14M of value-creation differential. This genuine cost advantage can be monetized through higher bid prices (competitive advantage) or retained as superior returns (LP advantage)."},{q:`At the IC presentation for the Domain 4 capstone, Peter asks: "What's your biggest single risk to this deal?" The correct response is:`,opts:["There are no material risks","Identify the specific, deal-critical risk with highest probability of occurring (e.g., lease-up extends to 15 months), explain its financial impact on IRR, and describe your mitigation strategy","Cap rate expansion in general","Interest rate risk"],a:1,exp:`IC expects specific, deal-aware risk identification. Generic answers ("interest rates could rise") show shallow analysis. Specific answers ("if lease-up extends to 15 months from our 9-month base case, IRR drops from 16% to 12% — here's how we mitigate: active pre-leasing campaign starting at acquisition") demonstrate mastery.`},{q:"Full-cycle return for a 5-year value-add industrial deal: buy at $16M, invest $1.5M renovation, exit at $23M. Total profit before equity multiple calculation:",opts:["$5.5M","$7M","$23M","$1.5M"],a:0,exp:"Total invested: $16M + $1.5M = $17.5M. Exit: $23M. Profit: $23M − $17.5M = $5.5M (before financing costs and time value)."},{q:"A well-structured Domain 4 capstone investment memo is approximately:",opts:["50 pages with all financial calculations","8–12 pages: exec summary, market overview, asset description, investment thesis, financial model summary, waterfall, sensitivity, risks, and recommendation — concise enough for busy IC, complete enough to defend","One page only","25 slides minimum"],a:1,exp:"IC memos balance completeness with concision. 8–12 pages with clear sections allows thorough IC review without overwhelming. Supporting detail (full DCF, comp grid, market data) goes in appendices. The main body is the decision document; appendices are the evidence."},{q:"Domain 4 builds on Domain 1 (Real Estate Development) primarily because:",opts:["Domain 1 and 4 are completely independent","Domain 1 covers pro forma, capital stack, and YOC mechanics — Domain 4 extends these into full investment analysis: DCF, JV structuring, market analysis, and disposition — using the same fundamental income approach but adding the full investment lifecycle","Domain 4 only applies to multifamily, Domain 1 to industrial","Domain 1 is for building; Domain 4 is for selling"],a:1,exp:"Domain 1 builds the foundation: NOI, cap rate, LTV, DSCR, capital stack, entitlement. Domain 4 extends this into a complete investment platform: DCF, IRR, JV waterfall, market analysis, value-add strategy, asset management, and disposition optimization."},{q:'An IC member challenges: "Your 3% rent growth assumption seems high given the supply pipeline." The correct response is:',opts:["Agree and reduce to 1% immediately",'Defend with data: "The pipeline of 1.2M SF delivers over 18 months against 2.1M SF of annual absorption — net demand still exceeds supply. Historical 10-year CAGR for this submarket is 3.2%. We believe 3% is supported." Then offer to show the stress case at 2%.',"Disagree and hold your position","Remove rent growth from the model entirely"],a:1,exp:"Defending assumptions under pressure is a key IC skill. Lead with data (historical CAGR, pipeline vs. absorption), acknowledge the concern, then offer the stress case. Shows you anticipated the question and prepared the answer."},{q:"Return attribution: deal A has 80% of returns from NOI growth; deal B has 80% from exit cap compression. In a rising rate environment, which deal has lower risk?",opts:["Deal B — cap rate compression is more certain","Deal A — returns driven by NOI growth (actual income increases) are less dependent on market conditions than cap rate movements","Equal risk","Cannot determine without more information"],a:1,exp:"In a rising rate environment, cap rate compression is unlikely (cap rates tend to follow rates up). Deal A's NOI-growth-driven returns are achievable even if rates rise. Deal B relies on cap rates falling — directly opposed to the rising rate environment thesis."},{q:"Completing Domain 4 means the student can perform all of the following EXCEPT:",opts:["Underwrite a 10-year DCF and calculate IRR","Build and execute a 1031 exchange from scratch without a QI","Present an investment memo to an IC","Structure a JV waterfall and calculate GP promote"],a:1,exp:"1031 exchanges must be managed by a licensed QI — the investor does not execute independently. Domain 4 teaches you to understand, plan, and optimize a 1031 strategy. The actual execution requires a licensed QI (not a skill HTA does alone)."},{q:"The HTA Builder Academy program integrates all 4 domains. Which correctly describes how they connect?",opts:["They are independent — each domain can be used without the others","Domain 1 (development) builds the foundation; Domain 2 (construction) provides execution knowledge; Domain 3 (contracts) governs the legal framework; Domain 4 (investment) integrates them all into full-cycle investment analysis — a development project, constructed by HTA, documented in contracts, underwritten as a deal","Domain 4 is the only domain that matters for real estate careers","Domain 3 (contracts) is the most important for investment analysis"],a:1,exp:"The four domains reflect HTA's complete platform: develop it (D1), build it (D2), contract it (D3), invest in it (D4). A student who completes all four can originate, underwrite, execute, and exit a commercial real estate deal from end-to-end — the complete HTA/Infinity Capital skillset."},{q:"After completing the full HTA Builder Academy program, what single skill best demonstrates mastery?",opts:["Memorizing cap rate benchmarks","Presenting a defensible, data-supported go/no-go recommendation on a real deal to experienced principals, fielding challenging questions, and adjusting the analysis when new information arises — applied judgment, not just knowledge","Building a perfect Excel DCF model","Knowing all AIA contract articles by number"],a:1,exp:"Mastery = applied judgment under pressure. Knowing concepts is table stakes. The capstone test is: can you take a real deal, apply all four domains of knowledge, form an independent view, defend it to experienced principals who will challenge every assumption, and make a sound decision? That's the HTA Builder Academy goal."}]}};export{e as D,t as a};
